INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'news'), 'City Bus Route Changes', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A2/news/ex-news-A2-001.mp3', 'Starting next week, the number five bus will follow a new route through the city center. Passengers should check the updated timetable at the bus stop or on the website for more information.', 'A2', 2, 13, 33, '[{"index": 0, "transcript": "Starting next week, the number five bus will follow a new route through the city center.", "start_ms": 0, "end_ms": 6400}, {"index": 1, "transcript": "Passengers should check the updated timetable at the bus stop or on the website for more information.", "start_ms": 6400, "end_ms": 13200}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'news'), 'Local Election Results', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A2/news/ex-news-A2-002.mp3', 'The results of the local election were announced yesterday evening. Mrs. Chen won with sixty percent of the votes. She promised to improve public transportation and build new schools.', 'A2', 2, 13, 29, '[{"index": 0, "transcript": "The results of the local election were announced yesterday evening.", "start_ms": 0, "end_ms": 4000}, {"index": 1, "transcript": "Mrs.", "start_ms": 4000, "end_ms": 5500}, {"index": 2, "transcript": "Chen won with sixty percent of the votes.", "start_ms": 5500, "end_ms": 8700}, {"index": 3, "transcript": "She promised to improve public transportation and build new schools.", "start_ms": 8700, "end_ms": 12700}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'news'), 'Hospital Expansion Plan', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A2/news/ex-news-A2-003.mp3', 'The city hospital will add a new building next year. It will have fifty more beds and a modern emergency room. The mayor said this is very important for the community.', 'A2', 2, 12, 31, '[{"index": 0, "transcript": "The city hospital will add a new building next year.", "start_ms": 0, "end_ms": 4000}, {"index": 1, "transcript": "It will have fifty more beds and a modern emergency room.", "start_ms": 4000, "end_ms": 8400}, {"index": 2, "transcript": "The mayor said this is very important for the community.", "start_ms": 8400, "end_ms": 12400}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'news'), 'Summer Festival Announcement', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A2/news/ex-news-A2-004.mp3', 'The annual summer festival will take place from July tenth to July twelfth at Central Park. There will be live music, food stalls, and activities for children of all ages.', 'A2', 2, 12, 30, '[{"index": 0, "transcript": "The annual summer festival will take place from July tenth to July twelfth at Central Park.", "start_ms": 0, "end_ms": 6400}, {"index": 1, "transcript": "There will be live music, food stalls, and activities for children of all ages.", "start_ms": 6400, "end_ms": 12000}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'news'), 'Fire Department Rescue', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A2/news/ex-news-A2-005.mp3', 'Firefighters rescued a cat from a tall tree on Park Street yesterday afternoon. The cat had been stuck for two days. The owner was very grateful and thanked the fire department.', 'A2', 2, 13, 31, '[{"index": 0, "transcript": "Firefighters rescued a cat from a tall tree on Park Street yesterday afternoon.", "start_ms": 0, "end_ms": 5200}, {"index": 1, "transcript": "The cat had been stuck for two days.", "start_ms": 5200, "end_ms": 8400}, {"index": 2, "transcript": "The owner was very grateful and thanked the fire department.", "start_ms": 8400, "end_ms": 12400}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'news'), 'Economic Growth Report', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B1/news/ex-news-B1-001.mp3', 'The national economy grew by three point five percent in the last quarter, exceeding expectations set by financial analysts earlier this year. Experts believe this growth was largely driven by increased consumer spending during the holiday season and a strong performance in the technology sector. However, some economists warn that rising inflation could slow down progress in the coming months.', 'B1', 3, 65, 60, '[{"index": 0, "transcript": "The national economy grew by three point five percent in the last quarter, exceeding expectations set by financial analysts earlier this year.", "start_ms": 0, "end_ms": 8800}, {"index": 1, "transcript": "Experts believe this growth was largely driven by increased consumer spending during the holiday season and a strong performance in the technology sector.", "start_ms": 8800, "end_ms": 18000}, {"index": 2, "transcript": "However, some economists warn that rising inflation could slow down progress in the coming months.", "start_ms": 18000, "end_ms": 24000}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'news'), 'International Trade Agreement', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B1/news/ex-news-B1-002.mp3', 'Representatives from twelve countries signed a new trade agreement yesterday in Geneva. The deal is expected to reduce tariffs on agricultural products and manufactured goods by up to twenty percent over the next five years. Trade ministers expressed optimism that the agreement will boost economic cooperation and create thousands of new jobs across the participating nations.', 'B1', 3, 72, 56, '[{"index": 0, "transcript": "Representatives from twelve countries signed a new trade agreement yesterday in Geneva.", "start_ms": 0, "end_ms": 4800}, {"index": 1, "transcript": "The deal is expected to reduce tariffs on agricultural products and manufactured goods by up to twenty percent over the next five years.", "start_ms": 4800, "end_ms": 14000}, {"index": 2, "transcript": "Trade ministers expressed optimism that the agreement will boost economic cooperation and create thousands of new jobs across the participating nations.", "start_ms": 14000, "end_ms": 22400}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'news'), 'Technology Company Layoffs', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B1/news/ex-news-B1-003.mp3', 'A major technology company announced plans to lay off approximately three thousand employees as part of a restructuring effort. The company said the decision was necessary to focus on core business areas including artificial intelligence and cloud computing. Affected workers will receive severance packages and career transition support over the next six months.', 'B1', 3, 68, 53, '[{"index": 0, "transcript": "A major technology company announced plans to lay off approximately three thousand employees as part of a restructuring effort.", "start_ms": 0, "end_ms": 7600}, {"index": 1, "transcript": "The company said the decision was necessary to focus on core business areas including artificial intelligence and cloud computing.", "start_ms": 7600, "end_ms": 15200}, {"index": 2, "transcript": "Affected workers will receive severance packages and career transition support over the next six months.", "start_ms": 15200, "end_ms": 21200}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'news'), 'Renewable Energy Milestone', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B1/news/ex-news-B1-004.mp3', 'For the first time in history, renewable energy sources provided more than fifty percent of the country''s electricity last month. Solar and wind power led the way, while traditional coal plants continued their steady decline. Environmental groups celebrated the achievement but urged the government to set even more ambitious targets for the next decade.', 'B1', 3, 70, 54, '[{"index": 0, "transcript": "For the first time in history, renewable energy sources provided more than fifty percent of the country''s electricity last month.", "start_ms": 0, "end_ms": 8000}, {"index": 1, "transcript": "Solar and wind power led the way, while traditional coal plants continued their steady decline.", "start_ms": 8000, "end_ms": 14000}, {"index": 2, "transcript": "Environmental groups celebrated the achievement but urged the government to set even more ambitious targets for the next decade.", "start_ms": 14000, "end_ms": 21600}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'news'), 'Education Reform Debate', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B1/news/ex-news-B1-005.mp3', 'The education minister presented a new reform plan to parliament this week, proposing significant changes to the national curriculum. Under the new plan, students would spend more time on practical skills such as coding, financial literacy, and critical thinking. Teachers unions have responded with mixed reactions, with some welcoming the modernization while others worry about increased workload.', 'B1', 3, 75, 57, '[{"index": 0, "transcript": "The education minister presented a new reform plan to parliament this week, proposing significant changes to the national curriculum.", "start_ms": 0, "end_ms": 7600}, {"index": 1, "transcript": "Under the new plan, students would spend more time on practical skills such as coding, financial literacy, and critical thinking.", "start_ms": 7600, "end_ms": 15600}, {"index": 2, "transcript": "Teachers unions have responded with mixed reactions, with some welcoming the modernization while others worry about increased workload.", "start_ms": 15600, "end_ms": 22800}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'news'), 'Global Climate Summit Review', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B2/news/ex-news-B2-001.mp3', 'The annual Global Climate Summit concluded yesterday with delegates from over one hundred and ninety countries reaching a tentative agreement on emissions reduction targets. The proposed framework commits developed nations to cutting greenhouse gas emissions by forty five percent by twenty thirty five, while providing substantial financial assistance to developing countries for green energy transitions. Critics have argued that the agreement lacks enforceable mechanisms, pointing to the failure of previous accords to deliver meaningful results. Nevertheless, the United Nations Secretary General described the outcome as a historic step forward in the fight against climate change.', 'B2', 4, 36, 95, '[{"index": 0, "transcript": "The annual Global Climate Summit concluded yesterday with delegates from over one hundred and ninety countries reaching a tentative agreement on emissions reduction targets.", "start_ms": 0, "end_ms": 9600}, {"index": 1, "transcript": "The proposed framework commits developed nations to cutting greenhouse gas emissions by forty five percent by twenty thirty five, while providing substantial financial assistance to developing countries for green energy transitions.", "start_ms": 9600, "end_ms": 22000}, {"index": 2, "transcript": "Critics have argued that the agreement lacks enforceable mechanisms, pointing to the failure of previous accords to deliver meaningful results.", "start_ms": 22000, "end_ms": 30000}, {"index": 3, "transcript": "Nevertheless, the United Nations Secretary General described the outcome as a historic step forward in the fight against climate change.", "start_ms": 30000, "end_ms": 38000}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'news'), 'Pharmaceutical Breakthrough', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B2/news/ex-news-B2-002.mp3', 'Researchers at a leading pharmaceutical company have announced a breakthrough in the treatment of antibiotic resistant infections, which have become one of the most pressing public health challenges worldwide. The new drug, which completed phase three clinical trials last month, demonstrated a ninety two percent efficacy rate against several strains of bacteria that had previously been considered untreatable. If approved by regulatory authorities, the medication could be available to patients within eighteen months, potentially saving tens of thousands of lives annually in hospitals across the globe.', 'B2', 4, 30, 86, '[{"index": 0, "transcript": "Researchers at a leading pharmaceutical company have announced a breakthrough in the treatment of antibiotic resistant infections, which have become one of the most pressing public health challenges worldwide.", "start_ms": 0, "end_ms": 11600}, {"index": 1, "transcript": "The new drug, which completed phase three clinical trials last month, demonstrated a ninety two percent efficacy rate against several strains of bacteria that had previously been considered untreatable.", "start_ms": 11600, "end_ms": 23200}, {"index": 2, "transcript": "If approved by regulatory authorities, the medication could be available to patients within eighteen months, potentially saving tens of thousands of lives annually in hospitals across the globe.", "start_ms": 23200, "end_ms": 34400}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'news'), 'Cybersecurity Threat Analysis', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B2/news/ex-news-B2-003.mp3', 'Intelligence agencies across multiple Western nations have issued coordinated warnings about a significant increase in state sponsored cyber attacks targeting critical infrastructure systems. According to a classified briefing leaked to reporters, the attacks have primarily focused on energy grids, water treatment facilities, and financial networks. Government officials emphasized the need for both public and private sector organizations to enhance their cybersecurity protocols and invest in advanced threat detection systems. The development comes amid escalating geopolitical tensions that show no signs of easing in the near future.', 'B2', 4, 35, 86, '[{"index": 0, "transcript": "Intelligence agencies across multiple Western nations have issued coordinated warnings about a significant increase in state sponsored cyber attacks targeting critical infrastructure systems.", "start_ms": 0, "end_ms": 9200}, {"index": 1, "transcript": "According to a classified briefing leaked to reporters, the attacks have primarily focused on energy grids, water treatment facilities, and financial networks.", "start_ms": 9200, "end_ms": 18000}, {"index": 2, "transcript": "Government officials emphasized the need for both public and private sector organizations to enhance their cybersecurity protocols and invest in advanced threat detection systems.", "start_ms": 18000, "end_ms": 27600}, {"index": 3, "transcript": "The development comes amid escalating geopolitical tensions that show no signs of easing in the near future.", "start_ms": 27600, "end_ms": 34400}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'news'), 'Space Exploration Update', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B2/news/ex-news-B2-004.mp3', 'The international space agency consortium announced ambitious plans to establish a permanent research station on the lunar surface by twenty thirty two. The project, which carries an estimated price tag of one hundred and twenty billion dollars, would involve partnerships between government agencies and private aerospace companies from fifteen countries. Scientists say the base would serve as a critical stepping stone for future missions to Mars and beyond, enabling researchers to study the long term effects of reduced gravity on the human body while also testing technologies essential for deep space travel.', 'B2', 4, 31, 92, '[{"index": 0, "transcript": "The international space agency consortium announced ambitious plans to establish a permanent research station on the lunar surface by twenty thirty two.", "start_ms": 0, "end_ms": 8800}, {"index": 1, "transcript": "The project, which carries an estimated price tag of one hundred and twenty billion dollars, would involve partnerships between government agencies and private aerospace companies from fifteen countries.", "start_ms": 8800, "end_ms": 20000}, {"index": 2, "transcript": "Scientists say the base would serve as a critical stepping stone for future missions to Mars and beyond, enabling researchers to study the long term effects of reduced gravity on the human body while also testing technologies essential for deep space travel.", "start_ms": 20000, "end_ms": 36800}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'news'), 'Immigration Policy Overhaul', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B2/news/ex-news-B2-005.mp3', 'The government has unveiled a comprehensive overhaul of the nation''s immigration system, introducing a points based framework that prioritizes skilled workers, entrepreneurs, and individuals with advanced academic qualifications. Under the new system, applicants would be assessed on criteria including language proficiency, work experience, educational attainment, and age. The proposal has sparked intense debate among lawmakers, with supporters arguing it will address critical labor shortages in sectors like healthcare and engineering, while opponents contend it fails to adequately address humanitarian obligations toward refugees and asylum seekers.', 'B2', 4, 36, 85, '[{"index": 0, "transcript": "The government has unveiled a comprehensive overhaul of the nation''s immigration system, introducing a points based framework that prioritizes skilled workers, entrepreneurs, and individuals with advanced academic qualifications.", "start_ms": 0, "end_ms": 11200}, {"index": 1, "transcript": "Under the new system, applicants would be assessed on criteria including language proficiency, work experience, educational attainment, and age.", "start_ms": 11200, "end_ms": 18800}, {"index": 2, "transcript": "The proposal has sparked intense debate among lawmakers, with supporters arguing it will address critical labor shortages in sectors like healthcare and engineering, while opponents contend it fails to adequately address humanitarian obligations toward refugees and asylum seekers.", "start_ms": 18800, "end_ms": 34000}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'news'), 'Geopolitical Tensions Analysis', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/C1/news/ex-news-C1-001.mp3', 'The rapidly deteriorating diplomatic relations between the two economic superpowers have sent shockwaves through global financial markets, with the benchmark stock index plummeting by nearly seven percent in a single trading session. Analysts attribute the precipitous decline to a combination of factors, including the imposition of sweeping trade sanctions, the mutual expulsion of diplomatic personnel, and increasingly bellicose rhetoric emanating from senior officials on both sides. International mediators have expressed grave concern that the escalation could precipitate a broader economic downturn affecting supply chains across Southeast Asia and Europe. Furthermore, defense analysts warn that the deployment of naval assets in contested maritime zones has raised the specter of military confrontation to levels not seen since the Cold War era, prompting urgent calls for de-escalation from the United Nations Security Council.', 'C1', 5, 47, 130, '[{"index": 0, "transcript": "The rapidly deteriorating diplomatic relations between the two economic superpowers have sent shockwaves through global financial markets, with the benchmark stock index plummeting by nearly seven percent in a single trading session.", "start_ms": 0, "end_ms": 12800}, {"index": 1, "transcript": "Analysts attribute the precipitous decline to a combination of factors, including the imposition of sweeping trade sanctions, the mutual expulsion of diplomatic personnel, and increasingly bellicose rhetoric emanating from senior officials on both sides.", "start_ms": 12800, "end_ms": 26400}, {"index": 2, "transcript": "International mediators have expressed grave concern that the escalation could precipitate a broader economic downturn affecting supply chains across Southeast Asia and Europe.", "start_ms": 26400, "end_ms": 35600}, {"index": 3, "transcript": "Furthermore, defense analysts warn that the deployment of naval assets in contested maritime zones has raised the specter of military confrontation to levels not seen since the Cold War era, prompting urgent calls for de-escalation from the United Nations Security Council.", "start_ms": 35600, "end_ms": 52000}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'news'), 'Healthcare System Under Pressure', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/C1/news/ex-news-C1-002.mp3', 'A comprehensive audit of the national healthcare system has revealed systemic inefficiencies that are costing taxpayers an estimated fourteen billion dollars annually while simultaneously failing to deliver adequate care to marginalized communities. The three hundred page report, commissioned by the parliamentary health committee and conducted by an independent panel of medical professionals, economists, and policy experts, identifies chronic understaffing, outdated information technology infrastructure, and fragmented administrative processes as the primary contributors to what the authors describe as a crisis of institutional capability. Perhaps most alarmingly, the audit found that patients in rural areas wait on average three times longer for specialist consultations compared to their urban counterparts, a disparity that has been widening steadily over the past decade despite repeated government pledges to address regional healthcare inequities.', 'C1', 5, 44, 127, '[{"index": 0, "transcript": "A comprehensive audit of the national healthcare system has revealed systemic inefficiencies that are costing taxpayers an estimated fourteen billion dollars annually while simultaneously failing to deliver adequate care to marginalized communities.", "start_ms": 0, "end_ms": 12800}, {"index": 1, "transcript": "The three hundred page report, commissioned by the parliamentary health committee and conducted by an independent panel of medical professionals, economists, and policy experts, identifies chronic understaffing, outdated information technology infrastructure, and fragmented administrative processes as the primary contributors to what the authors describe as a crisis of institutional capability.", "start_ms": 12800, "end_ms": 32800}, {"index": 2, "transcript": "Perhaps most alarmingly, the audit found that patients in rural areas wait on average three times longer for specialist consultations compared to their urban counterparts, a disparity that has been widening steadily over the past decade despite repeated government pledges to address regional healthcare inequities.", "start_ms": 32800, "end_ms": 50800}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'news'), 'AI Regulation Debate', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/C1/news/ex-news-C1-003.mp3', 'The European Commission has proposed sweeping new legislation aimed at establishing the world''s most comprehensive regulatory framework for artificial intelligence, a move that has ignited fierce debate among technology executives, civil liberties advocates, and government officials across the continent. The proposed AI Act would classify artificial intelligence applications into risk tiers ranging from minimal to unacceptable, with the most stringent requirements reserved for systems deployed in critical domains such as law enforcement, healthcare diagnostics, and autonomous vehicle navigation. Technology companies have pushed back vigorously, arguing that excessive regulation will stifle innovation and drive investment toward jurisdictions with more permissive regulatory environments. Meanwhile, privacy advocates have criticized the proposal for not going far enough, particularly with regard to the use of real time biometric surveillance systems in public spaces, which they argue poses an existential threat to fundamental civil liberties.', 'C1', 5, 52, 139, '[{"index": 0, "transcript": "The European Commission has proposed sweeping new legislation aimed at establishing the world''s most comprehensive regulatory framework for artificial intelligence, a move that has ignited fierce debate among technology executives, civil liberties advocates, and government officials across the continent.", "start_ms": 0, "end_ms": 15600}, {"index": 1, "transcript": "The proposed AI Act would classify artificial intelligence applications into risk tiers ranging from minimal to unacceptable, with the most stringent requirements reserved for systems deployed in critical domains such as law enforcement, healthcare diagnostics, and autonomous vehicle navigation.", "start_ms": 15600, "end_ms": 31200}, {"index": 2, "transcript": "Technology companies have pushed back vigorously, arguing that excessive regulation will stifle innovation and drive investment toward jurisdictions with more permissive regulatory environments.", "start_ms": 31200, "end_ms": 40400}, {"index": 3, "transcript": "Meanwhile, privacy advocates have criticized the proposal for not going far enough, particularly with regard to the use of real time biometric surveillance systems in public spaces, which they argue poses an existential threat to fundamental civil liberties.", "start_ms": 40400, "end_ms": 55600}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'news'), 'Financial Markets Volatility Report', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/C1/news/ex-news-C1-004.mp3', 'Central banks across the developed world are grappling with an unprecedented policy dilemma as persistent inflationary pressures collide with mounting signs of economic stagnation, creating conditions that economists have begun referring to as a potential stagflationary spiral. The Federal Reserve''s decision to maintain interest rates at their current elevated levels despite three consecutive quarters of declining gross domestic product growth has drawn sharp criticism from both Wall Street analysts who fear a prolonged recession and progressive economists who argue that monetary policy alone is insufficient to address structural imbalances in the labor market. Adding to the complexity of the situation, recent data indicates that consumer confidence has fallen to its lowest point in over a decade, while corporate debt levels have reached historically dangerous proportions, raising the specter of a cascading series of defaults that could destabilize the broader financial system.', 'C1', 5, 45, 141, '[{"index": 0, "transcript": "Central banks across the developed world are grappling with an unprecedented policy dilemma as persistent inflationary pressures collide with mounting signs of economic stagnation, creating conditions that economists have begun referring to as a potential stagflationary spiral.", "start_ms": 0, "end_ms": 14800}, {"index": 1, "transcript": "The Federal Reserve''s decision to maintain interest rates at their current elevated levels despite three consecutive quarters of declining gross domestic product growth has drawn sharp criticism from both Wall Street analysts who fear a prolonged recession and progressive economists who argue that monetary policy alone is insufficient to address structural imbalances in the labor market.", "start_ms": 14800, "end_ms": 37200}, {"index": 2, "transcript": "Adding to the complexity of the situation, recent data indicates that consumer confidence has fallen to its lowest point in over a decade, while corporate debt levels have reached historically dangerous proportions, raising the specter of a cascading series of defaults that could destabilize the broader financial system.", "start_ms": 37200, "end_ms": 56400}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'news'), 'Global Migration Crisis Coverage', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/C1/news/ex-news-C1-005.mp3', 'The United Nations High Commissioner for Refugees has issued its most urgent appeal in decades, warning that the convergence of armed conflicts, climate induced displacement, and economic collapse in multiple regions has created what officials are now characterizing as an existential challenge to the international humanitarian system. According to the latest figures compiled by the agency, approximately one hundred and fourteen million people worldwide have been forcibly displaced from their homes, a staggering number that exceeds the entire population of most European nations. The report highlights particularly dire conditions in sub-Saharan Africa and Central America, where prolonged droughts, gang violence, and government instability have created a self-reinforcing cycle of deprivation that drives ever increasing numbers of people to undertake perilous journeys in search of safety and economic opportunity.', 'C1', 5, 46, 128, '[{"index": 0, "transcript": "The United Nations High Commissioner for Refugees has issued its most urgent appeal in decades, warning that the convergence of armed conflicts, climate induced displacement, and economic collapse in multiple regions has created what officials are now characterizing as an existential challenge to the international humanitarian system.", "start_ms": 0, "end_ms": 18800}, {"index": 1, "transcript": "According to the latest figures compiled by the agency, approximately one hundred and fourteen million people worldwide have been forcibly displaced from their homes, a staggering number that exceeds the entire population of most European nations.", "start_ms": 18800, "end_ms": 33200}, {"index": 2, "transcript": "The report highlights particularly dire conditions in sub-Saharan Africa and Central America, where prolonged droughts, gang violence, and government instability have created a self-reinforcing cycle of deprivation that drives ever increasing numbers of people to undertake perilous journeys in search of safety and economic opportunity.", "start_ms": 33200, "end_ms": 51200}]'::jsonb);
