INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'movies'), 'Superhero Entrance', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A1/movies/ex-movies-A1-005.mp3', 'Do not worry. I am here to help. Everything will be okay.', 'A1', 1, 7, 12, '[{"index": 0, "transcript": "Do not worry.", "start_ms": 0, "end_ms": 1500}, {"index": 1, "transcript": "I am here to help.", "start_ms": 1500, "end_ms": 3500}, {"index": 2, "transcript": "Everything will be okay.", "start_ms": 3500, "end_ms": 5100}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'movies'), 'The Big Farewell', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A2/movies/ex-movies-A2-001.mp3', 'I have to go now, Sarah. My train leaves in thirty minutes. I promise I will come back soon. Please wait for me and take care of yourself.', 'A2', 2, 13, 28, '[{"index": 0, "transcript": "I have to go now, Sarah.", "start_ms": 0, "end_ms": 2400}, {"index": 1, "transcript": "My train leaves in thirty minutes.", "start_ms": 2400, "end_ms": 4800}, {"index": 2, "transcript": "I promise I will come back soon.", "start_ms": 4800, "end_ms": 7600}, {"index": 3, "transcript": "Please wait for me and take care of yourself.", "start_ms": 7600, "end_ms": 11200}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'movies'), 'Planning a Beach Trip', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A2/movies/ex-movies-A2-002.mp3', 'What are you doing this weekend? I was thinking we could drive to the beach and spend the day there. The weather forecast says it will be sunny and perfect for swimming.', 'A2', 2, 12, 32, '[{"index": 0, "transcript": "What are you doing this weekend?", "start_ms": 0, "end_ms": 2400}, {"index": 1, "transcript": "I was thinking we could drive to the beach and spend the day there.", "start_ms": 2400, "end_ms": 8000}, {"index": 2, "transcript": "The weather forecast says it will be sunny and perfect for swimming.", "start_ms": 8000, "end_ms": 12800}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'movies'), 'Discovery in the Attic', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A2/movies/ex-movies-A2-003.mp3', 'I found something amazing in the attic yesterday. It was an old photo of our grandparents from nineteen fifty two. They looked so young and happy standing in front of their first house.', 'A2', 2, 13, 33, '[{"index": 0, "transcript": "I found something amazing in the attic yesterday.", "start_ms": 0, "end_ms": 3200}, {"index": 1, "transcript": "It was an old photo of our grandparents from nineteen fifty two.", "start_ms": 3200, "end_ms": 8000}, {"index": 2, "transcript": "They looked so young and happy standing in front of their first house.", "start_ms": 8000, "end_ms": 13200}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'movies'), 'The Apology Scene', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A2/movies/ex-movies-A2-004.mp3', 'I know I was wrong. I should not have said those things to you. I am truly sorry and I want to make things right between us again.', 'A2', 2, 10, 28, '[{"index": 0, "transcript": "I know I was wrong.", "start_ms": 0, "end_ms": 2000}, {"index": 1, "transcript": "I should not have said those things to you.", "start_ms": 2000, "end_ms": 5600}, {"index": 2, "transcript": "I am truly sorry and I want to make things right between us again.", "start_ms": 5600, "end_ms": 11200}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'movies'), 'Meeting at the Cafe', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A2/movies/ex-movies-A2-005.mp3', 'I have been waiting here for almost an hour. Where were you? I called you three times but you did not answer your phone. I was really worried about you.', 'A2', 2, 12, 30, '[{"index": 0, "transcript": "I have been waiting here for almost an hour.", "start_ms": 0, "end_ms": 3600}, {"index": 1, "transcript": "Where were you?", "start_ms": 3600, "end_ms": 5100}, {"index": 2, "transcript": "I called you three times but you did not answer your phone.", "start_ms": 5100, "end_ms": 9900}, {"index": 3, "transcript": "I was really worried about you.", "start_ms": 9900, "end_ms": 12300}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'movies'), 'Courtroom Confession', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B1/movies/ex-movies-B1-001.mp3', 'Your Honor, I want to tell the truth. For months I kept this secret because I was afraid of what people would think. But I cannot carry this burden any longer. The real person behind the crime is standing right here in this courtroom, and it is not the man you have accused. It is me. I take full responsibility for my actions and I accept whatever punishment you decide.', 'B1', 3, 75, 70, '[{"index": 0, "transcript": "Your Honor, I want to tell the truth.", "start_ms": 0, "end_ms": 3200}, {"index": 1, "transcript": "For months I kept this secret because I was afraid of what people would think.", "start_ms": 3200, "end_ms": 9200}, {"index": 2, "transcript": "But I cannot carry this burden any longer.", "start_ms": 9200, "end_ms": 12400}, {"index": 3, "transcript": "The real person behind the crime is standing right here in this courtroom, and it is not the man you have accused.", "start_ms": 12400, "end_ms": 21200}, {"index": 4, "transcript": "It is me.", "start_ms": 21200, "end_ms": 22700}, {"index": 5, "transcript": "I take full responsibility for my actions and I accept whatever punishment you decide.", "start_ms": 22700, "end_ms": 28300}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'movies'), 'Farewell at the Airport', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B1/movies/ex-movies-B1-002.mp3', 'Promise me that you will write to me every week and that you will come back before the summer ends. I know the distance will be hard, but I believe our friendship is strong enough to survive anything. Take care of yourself over there and do not forget where you come from. We will all be here waiting for you when you return.', 'B1', 3, 70, 63, '[{"index": 0, "transcript": "Promise me that you will write to me every week and that you will come back before the summer ends.", "start_ms": 0, "end_ms": 8000}, {"index": 1, "transcript": "I know the distance will be hard, but I believe our friendship is strong enough to survive anything.", "start_ms": 8000, "end_ms": 15200}, {"index": 2, "transcript": "Take care of yourself over there and do not forget where you come from.", "start_ms": 15200, "end_ms": 20800}, {"index": 3, "transcript": "We will all be here waiting for you when you return.", "start_ms": 20800, "end_ms": 25200}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'movies'), 'The Detective''s Theory', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B1/movies/ex-movies-B1-003.mp3', 'Listen carefully because this is where it all starts to make sense. The killer did not enter through the front door. I examined the lock myself and there were no signs of forced entry. Instead, they came through the basement window which was conveniently left open that night. Someone on the inside wanted this to happen. The question is who had both the motive and the opportunity.', 'B1', 3, 78, 67, '[{"index": 0, "transcript": "Listen carefully because this is where it all starts to make sense.", "start_ms": 0, "end_ms": 4800}, {"index": 1, "transcript": "The killer did not enter through the front door.", "start_ms": 4800, "end_ms": 8400}, {"index": 2, "transcript": "I examined the lock myself and there were no signs of forced entry.", "start_ms": 8400, "end_ms": 13600}, {"index": 3, "transcript": "Instead, they came through the basement window which was conveniently left open that night.", "start_ms": 13600, "end_ms": 19200}, {"index": 4, "transcript": "Someone on the inside wanted this to happen.", "start_ms": 19200, "end_ms": 22400}, {"index": 5, "transcript": "The question is who had both the motive and the opportunity.", "start_ms": 22400, "end_ms": 26800}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'movies'), 'Inspiring Coach Speech', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B1/movies/ex-movies-B1-004.mp3', 'I know you are tired. I know your legs hurt and your lungs are burning. But let me tell you something. The other team is just as tired as you are. The difference is whether you can push through the pain and find something deep inside yourself that refuses to give up. That is what separates champions from everyone else. Now get out there and show them what you are made of.', 'B1', 3, 73, 72, '[{"index": 0, "transcript": "I know you are tired.", "start_ms": 0, "end_ms": 2000}, {"index": 1, "transcript": "I know your legs hurt and your lungs are burning.", "start_ms": 2000, "end_ms": 6000}, {"index": 2, "transcript": "But let me tell you something.", "start_ms": 6000, "end_ms": 8400}, {"index": 3, "transcript": "The other team is just as tired as you are.", "start_ms": 8400, "end_ms": 12400}, {"index": 4, "transcript": "The difference is whether you can push through the pain and find something deep inside yourself that refuses to give up.", "start_ms": 12400, "end_ms": 20800}, {"index": 5, "transcript": "That is what separates champions from everyone else.", "start_ms": 20800, "end_ms": 24000}, {"index": 6, "transcript": "Now get out there and show them what you are made of.", "start_ms": 24000, "end_ms": 28800}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'movies'), 'Midnight Revelation', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B1/movies/ex-movies-B1-005.mp3', 'I finally understand now. All these years I spent chasing success and money, thinking that would make me happy. But the truth is the happiest moments of my life were the simplest ones. Having dinner with my family on Sunday evenings. Walking the dog in the park. Reading bedtime stories to my daughter. Those are the things that truly matter, and I nearly lost them all.', 'B1', 3, 80, 66, '[{"index": 0, "transcript": "I finally understand now.", "start_ms": 0, "end_ms": 1600}, {"index": 1, "transcript": "All these years I spent chasing success and money, thinking that would make me happy.", "start_ms": 1600, "end_ms": 7600}, {"index": 2, "transcript": "But the truth is the happiest moments of my life were the simplest ones.", "start_ms": 7600, "end_ms": 13200}, {"index": 3, "transcript": "Having dinner with my family on Sunday evenings.", "start_ms": 13200, "end_ms": 16400}, {"index": 4, "transcript": "Walking the dog in the park.", "start_ms": 16400, "end_ms": 18800}, {"index": 5, "transcript": "Reading bedtime stories to my daughter.", "start_ms": 18800, "end_ms": 21200}, {"index": 6, "transcript": "Those are the things that truly matter, and I nearly lost them all.", "start_ms": 21200, "end_ms": 26400}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'movies'), 'Villain''s Monologue', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B2/movies/ex-movies-B2-001.mp3', 'You see, the problem with heroes is that they operate under the delusion that the world can be neatly divided into good and evil. But I have spent decades observing human nature, and I can assure you the reality is far more complicated than that simplistic worldview allows. Every person in this city has darkness within them, hidden desires and selfish impulses they suppress in the name of civility. All I have done is provide them with an opportunity to embrace their true selves.', 'B2', 4, 25, 84, '[{"index": 0, "transcript": "You see, the problem with heroes is that they operate under the delusion that the world can be neatly divided into good and evil.", "start_ms": 0, "end_ms": 9600}, {"index": 1, "transcript": "But I have spent decades observing human nature, and I can assure you the reality is far more complicated than that simplistic worldview allows.", "start_ms": 9600, "end_ms": 19200}, {"index": 2, "transcript": "Every person in this city has darkness within them, hidden desires and selfish impulses they suppress in the name of civility.", "start_ms": 19200, "end_ms": 27600}, {"index": 3, "transcript": "All I have done is provide them with an opportunity to embrace their true selves.", "start_ms": 27600, "end_ms": 33600}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'movies'), 'War Veteran''s Reflection', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B2/movies/ex-movies-B2-002.mp3', 'They never tell you about the silence that comes after the battle. Everyone talks about the explosions, the chaos, the adrenaline coursing through your veins when you are fighting for your life. But nobody prepares you for the quiet moments afterward, when you sit alone in the dark replaying every decision you made and wondering whether the person sitting next to you at breakfast would still be alive if you had turned left instead of right. That kind of guilt does not wash away with time.', 'B2', 4, 25, 86, '[{"index": 0, "transcript": "They never tell you about the silence that comes after the battle.", "start_ms": 0, "end_ms": 4800}, {"index": 1, "transcript": "Everyone talks about the explosions, the chaos, the adrenaline coursing through your veins when you are fighting for your life.", "start_ms": 4800, "end_ms": 12800}, {"index": 2, "transcript": "But nobody prepares you for the quiet moments afterward, when you sit alone in the dark replaying every decision you made and wondering whether the person sitting next to you at breakfast would still be alive if you had turned left instead of right.", "start_ms": 12800, "end_ms": 30400}, {"index": 3, "transcript": "That kind of guilt does not wash away with time.", "start_ms": 30400, "end_ms": 34400}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'movies'), 'The Scientist''s Warning', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B2/movies/ex-movies-B2-003.mp3', 'We have approximately fourteen months before the anomaly reaches a critical threshold, at which point the consequences will be catastrophic and irreversible. I understand that my findings contradict everything the committee has been telling the public, and I know that presenting this data will effectively end my career. But I took an oath when I became a scientist to pursue truth regardless of personal cost, and the truth is that we are running out of time.', 'B2', 4, 23, 76, '[{"index": 0, "transcript": "We have approximately fourteen months before the anomaly reaches a critical threshold, at which point the consequences will be catastrophic and irreversible.", "start_ms": 0, "end_ms": 8800}, {"index": 1, "transcript": "I understand that my findings contradict everything the committee has been telling the public, and I know that presenting this data will effectively end my career.", "start_ms": 8800, "end_ms": 19200}, {"index": 2, "transcript": "But I took an oath when I became a scientist to pursue truth regardless of personal cost, and the truth is that we are running out of time.", "start_ms": 19200, "end_ms": 30400}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'movies'), 'Reconciliation Scene', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B2/movies/ex-movies-B2-004.mp3', 'I spent fifteen years blaming you for everything that went wrong in my life. Every failed relationship, every missed opportunity, every sleepless night, I traced back to that moment when you walked out the door without looking back. But somewhere along the way, I realized that holding onto that resentment was destroying me far more effectively than anything you ever did. So I am not here to demand an apology or an explanation. I am here because I need to forgive you, not for your sake, but for mine.', 'B2', 4, 28, 89, '[{"index": 0, "transcript": "I spent fifteen years blaming you for everything that went wrong in my life.", "start_ms": 0, "end_ms": 5600}, {"index": 1, "transcript": "Every failed relationship, every missed opportunity, every sleepless night, I traced back to that moment when you walked out the door without looking back.", "start_ms": 5600, "end_ms": 15200}, {"index": 2, "transcript": "But somewhere along the way, I realized that holding onto that resentment was destroying me far more effectively than anything you ever did.", "start_ms": 15200, "end_ms": 24400}, {"index": 3, "transcript": "So I am not here to demand an apology or an explanation.", "start_ms": 24400, "end_ms": 29200}, {"index": 4, "transcript": "I am here because I need to forgive you, not for your sake, but for mine.", "start_ms": 29200, "end_ms": 35600}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'movies'), 'Time Traveler''s Dilemma', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B2/movies/ex-movies-B2-005.mp3', 'Here is the paradox that nobody explains when they hand you the keys to a time machine. Every change you make, no matter how small or well intentioned, creates ripple effects that cascade through decades in ways that are completely unpredictable. I went back to save one life and in doing so inadvertently altered the circumstances that led to the birth of three thousand people who now simply do not exist. The moral calculus of temporal intervention is not something any human being is equipped to handle.', 'B2', 4, 27, 87, '[{"index": 0, "transcript": "Here is the paradox that nobody explains when they hand you the keys to a time machine.", "start_ms": 0, "end_ms": 6800}, {"index": 1, "transcript": "Every change you make, no matter how small or well intentioned, creates ripple effects that cascade through decades in ways that are completely unpredictable.", "start_ms": 6800, "end_ms": 16400}, {"index": 2, "transcript": "I went back to save one life and in doing so inadvertently altered the circumstances that led to the birth of three thousand people who now simply do not exist.", "start_ms": 16400, "end_ms": 28400}, {"index": 3, "transcript": "The moral calculus of temporal intervention is not something any human being is equipped to handle.", "start_ms": 28400, "end_ms": 34800}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'movies'), 'Philosophical Monologue on Identity', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/C1/movies/ex-movies-C1-001.mp3', 'What defines us is not merely the choices we make in moments of comfort but rather how we respond when confronted with adversity and the unknown stretches of our own limitations. I have spent the better part of three decades constructing an elaborate facade of competence and self-assurance, carefully curating every interaction to project an image of someone who has life figured out. But standing here now, stripped of every pretense and every carefully rehearsed response, I am forced to confront the terrifying possibility that the person I have been pretending to be all these years bears almost no resemblance to the frightened, uncertain individual who stares back at me from the mirror each morning. The irony is not lost on me that it took losing everything I thought I valued to discover that authenticity was the only path to genuine peace.', 'C1', 5, 39, 142, '[{"index": 0, "transcript": "What defines us is not merely the choices we make in moments of comfort but rather how we respond when confronted with adversity and the unknown stretches of our own limitations.", "start_ms": 0, "end_ms": 12400}, {"index": 1, "transcript": "I have spent the better part of three decades constructing an elaborate facade of competence and self-assurance, carefully curating every interaction to project an image of someone who has life figured out.", "start_ms": 12400, "end_ms": 25200}, {"index": 2, "transcript": "But standing here now, stripped of every pretense and every carefully rehearsed response, I am forced to confront the terrifying possibility that the person I have been pretending to be all these years bears almost no resemblance to the frightened, uncertain individual who stares back at me from the mirror each morning.", "start_ms": 25200, "end_ms": 46000}, {"index": 3, "transcript": "The irony is not lost on me that it took losing everything I thought I valued to discover that authenticity was the only path to genuine peace.", "start_ms": 46000, "end_ms": 56800}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'movies'), 'The General''s Final Address', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/C1/movies/ex-movies-C1-002.mp3', 'Soldiers, I will not insult your intelligence with hollow promises of glory or fabricated assurances that everyone standing in this formation will see tomorrow''s sunrise. The reality of what we face is sobering and unambiguous. The enemy outnumbers us roughly three to one, they hold the strategic high ground, and our supply lines have been compromised for the better part of a fortnight. By every conventional metric of military analysis, the odds are overwhelmingly against us. But here is what I also know to be true. I know the character of the men and women who stand beside me today. I have witnessed your courage under impossible circumstances, your unwavering commitment to one another, and your refusal to surrender even when every rational calculation suggested that continuing to fight was futile.', 'C1', 5, 42, 131, '[{"index": 0, "transcript": "Soldiers, I will not insult your intelligence with hollow promises of glory or fabricated assurances that everyone standing in this formation will see tomorrow''s sunrise.", "start_ms": 0, "end_ms": 10000}, {"index": 1, "transcript": "The reality of what we face is sobering and unambiguous.", "start_ms": 10000, "end_ms": 14000}, {"index": 2, "transcript": "The enemy outnumbers us roughly three to one, they hold the strategic high ground, and our supply lines have been compromised for the better part of a fortnight.", "start_ms": 14000, "end_ms": 25200}, {"index": 3, "transcript": "By every conventional metric of military analysis, the odds are overwhelmingly against us.", "start_ms": 25200, "end_ms": 30400}, {"index": 4, "transcript": "But here is what I also know to be true.", "start_ms": 30400, "end_ms": 34400}, {"index": 5, "transcript": "I know the character of the men and women who stand beside me today.", "start_ms": 34400, "end_ms": 40000}, {"index": 6, "transcript": "I have witnessed your courage under impossible circumstances, your unwavering commitment to one another, and your refusal to surrender even when every rational calculation suggested that continuing to fight was futile.", "start_ms": 40000, "end_ms": 52400}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'movies'), 'Existential Crisis at Midnight', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/C1/movies/ex-movies-C1-003.mp3', 'Do you ever lie awake at three in the morning contemplating the sheer improbability of your own existence? Consider for a moment the astronomical chain of coincidences that had to unfold in precisely the right sequence for you to be lying here, in this particular bed, in this particular city, having this particular conversation. Every ancestor who survived famine and plague and war, every chance encounter between strangers that eventually led to the union that produced the next generation, every split second decision to turn left instead of right that prevented a fatal accident. The mathematical probability of any specific individual existing is so vanishingly small as to be essentially indistinguishable from zero, and yet here we are, blessed or cursed with consciousness.', 'C1', 5, 37, 123, '[{"index": 0, "transcript": "Do you ever lie awake at three in the morning contemplating the sheer improbability of your own existence?", "start_ms": 0, "end_ms": 7200}, {"index": 1, "transcript": "Consider for a moment the astronomical chain of coincidences that had to unfold in precisely the right sequence for you to be lying here, in this particular bed, in this particular city, having this particular conversation.", "start_ms": 7200, "end_ms": 21600}, {"index": 2, "transcript": "Every ancestor who survived famine and plague and war, every chance encounter between strangers that eventually led to the union that produced the next generation, every split second decision to turn left instead of right that prevented a fatal accident.", "start_ms": 21600, "end_ms": 37600}, {"index": 3, "transcript": "The mathematical probability of any specific individual existing is so vanishingly small as to be essentially indistinguishable from zero, and yet here we are, blessed or cursed with consciousness.", "start_ms": 37600, "end_ms": 49200}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'movies'), 'Revolutionary''s Manifesto', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/C1/movies/ex-movies-C1-004.mp3', 'The system you have built, this gleaming monument to controlled inequality, operates on a fundamental assumption that you have never been forced to examine because the consequences of that examination would be devastating to those who benefit from the status quo. You have constructed elaborate mechanisms of social control, educational institutions that reward conformity over creativity, economic structures that concentrate wealth among those who already possess it, and media apparatus that manufactures consent by framing the interests of the powerful as the natural order of things. But what you have failed to account for is the cumulative effect of millions of small acts of resistance, each one individually insignificant but collectively capable of generating transformative pressure.', 'C1', 5, 39, 116, '[{"index": 0, "transcript": "The system you have built, this gleaming monument to controlled inequality, operates on a fundamental assumption that you have never been forced to examine because the consequences of that examination would be devastating to those who benefit from the status quo.", "start_ms": 0, "end_ms": 16400}, {"index": 1, "transcript": "You have constructed elaborate mechanisms of social control, educational institutions that reward conformity over creativity, economic structures that concentrate wealth among those who already possess it, and media apparatus that manufactures consent by framing the interests of the powerful as the natural order of things.", "start_ms": 16400, "end_ms": 34400}, {"index": 2, "transcript": "But what you have failed to account for is the cumulative effect of millions of small acts of resistance, each one individually insignificant but collectively capable of generating transformative pressure.", "start_ms": 34400, "end_ms": 46400}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'movies'), 'Dying Character''s Last Words', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/C1/movies/ex-movies-C1-005.mp3', 'Come closer because I do not have much time left and there are things I need to say that I should have said years ago when saying them might have actually mattered. I spent my entire life building walls around my heart, convincing myself that emotional vulnerability was a weakness that others would inevitably exploit. Every time someone tried to get close, I found increasingly creative ways to push them away. But lying here now, watching the last grains of sand slip through the hourglass, I can see with devastating clarity what my stubborn pride has cost me. The tragedy is not that I am dying. The tragedy is that I am dying surrounded by the echoes of relationships I deliberately destroyed. The walls we build to protect ourselves from pain are the same walls that prevent us from experiencing the very connections that give life its meaning.', 'C1', 5, 42, 148, '[{"index": 0, "transcript": "Come closer because I do not have much time left and there are things I need to say that I should have said years ago when saying them might have actually mattered.", "start_ms": 0, "end_ms": 12800}, {"index": 1, "transcript": "I spent my entire life building walls around my heart, convincing myself that emotional vulnerability was a weakness that others would inevitably exploit.", "start_ms": 12800, "end_ms": 22000}, {"index": 2, "transcript": "Every time someone tried to get close, I found increasingly creative ways to push them away.", "start_ms": 22000, "end_ms": 28400}, {"index": 3, "transcript": "But lying here now, watching the last grains of sand slip through the hourglass, I can see with devastating clarity what my stubborn pride has cost me.", "start_ms": 28400, "end_ms": 39200}, {"index": 4, "transcript": "The tragedy is not that I am dying.", "start_ms": 39200, "end_ms": 42400}, {"index": 5, "transcript": "The tragedy is that I am dying surrounded by the echoes of relationships I deliberately destroyed.", "start_ms": 42400, "end_ms": 48800}, {"index": 6, "transcript": "The walls we build to protect ourselves from pain are the same walls that prevent us from experiencing the very connections that give life its meaning.", "start_ms": 48800, "end_ms": 59200}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'songs'), 'You Are My Sunshine', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A1/songs/ex-songs-A1-001.mp3', 'You are my sunshine, my only sunshine. You make me happy when skies are gray.', 'A1', 1, 8, 15, '[{"index": 0, "transcript": "You are my sunshine, my only sunshine.", "start_ms": 0, "end_ms": 2800}, {"index": 1, "transcript": "You make me happy when skies are gray.", "start_ms": 2800, "end_ms": 6000}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'songs'), 'Happy Birthday Song', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A1/songs/ex-songs-A1-002.mp3', 'Happy birthday to you. Happy birthday, dear friend. I wish you all the best today.', 'A1', 1, 10, 15, '[{"index": 0, "transcript": "Happy birthday to you.", "start_ms": 0, "end_ms": 1600}, {"index": 1, "transcript": "Happy birthday, dear friend.", "start_ms": 1600, "end_ms": 3200}, {"index": 2, "transcript": "I wish you all the best today.", "start_ms": 3200, "end_ms": 6000}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'songs'), 'Counting Stars', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A1/songs/ex-songs-A1-003.mp3', 'One, two, three. I count the stars at night. They are so bright and beautiful.', 'A1', 1, 9, 15, '[{"index": 0, "transcript": "One, two, three.", "start_ms": 0, "end_ms": 1500}, {"index": 1, "transcript": "I count the stars at night.", "start_ms": 1500, "end_ms": 3900}, {"index": 2, "transcript": "They are so bright and beautiful.", "start_ms": 3900, "end_ms": 6300}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'songs'), 'Simple Love Melody', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A1/songs/ex-songs-A1-004.mp3', 'I love you so much. You are always in my heart. Please stay with me forever.', 'A1', 1, 9, 16, '[{"index": 0, "transcript": "I love you so much.", "start_ms": 0, "end_ms": 2000}, {"index": 1, "transcript": "You are always in my heart.", "start_ms": 2000, "end_ms": 4400}, {"index": 2, "transcript": "Please stay with me forever.", "start_ms": 4400, "end_ms": 6400}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'songs'), 'Morning Song', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A1/songs/ex-songs-A1-005.mp3', 'Good morning, world. The sun is up. It is a brand new day. Let us go and play.', 'A1', 1, 10, 18, '[{"index": 0, "transcript": "Good morning, world.", "start_ms": 0, "end_ms": 1500}, {"index": 1, "transcript": "The sun is up.", "start_ms": 1500, "end_ms": 3100}, {"index": 2, "transcript": "It is a brand new day.", "start_ms": 3100, "end_ms": 5500}, {"index": 3, "transcript": "Let us go and play.", "start_ms": 5500, "end_ms": 7500}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'songs'), 'Rainy Day Ballad', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A2/songs/ex-songs-A2-001.mp3', 'I will always remember the day we first met under the stars. You smiled at me and said hello. Since that moment, everything changed in my life forever and I knew we would be friends.', 'A2', 2, 14, 35, '[{"index": 0, "transcript": "I will always remember the day we first met under the stars.", "start_ms": 0, "end_ms": 4800}, {"index": 1, "transcript": "You smiled at me and said hello.", "start_ms": 4800, "end_ms": 7600}, {"index": 2, "transcript": "Since that moment, everything changed in my life forever and I knew we would be friends.", "start_ms": 7600, "end_ms": 14000}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'songs'), 'Road Trip Song', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A2/songs/ex-songs-A2-002.mp3', 'We are driving down the highway with the windows open wide. The wind is in our hair and the music plays so loud. Every mile takes us further from the things we left behind and closer to the dreams we have been chasing all our lives.', 'A2', 2, 18, 46, '[{"index": 0, "transcript": "We are driving down the highway with the windows open wide.", "start_ms": 0, "end_ms": 4400}, {"index": 1, "transcript": "The wind is in our hair and the music plays so loud.", "start_ms": 4400, "end_ms": 9200}, {"index": 2, "transcript": "Every mile takes us further from the things we left behind and closer to the dreams we have been chasing all our lives.", "start_ms": 9200, "end_ms": 18400}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'songs'), 'Goodbye Summer', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A2/songs/ex-songs-A2-003.mp3', 'The leaves are falling down and summer days are gone. I miss the sunshine and the laughter that we shared. But I know that every ending is a chance to start again. So I will hold these memories close until the warm days come back.', 'A2', 2, 17, 45, '[{"index": 0, "transcript": "The leaves are falling down and summer days are gone.", "start_ms": 0, "end_ms": 4000}, {"index": 1, "transcript": "I miss the sunshine and the laughter that we shared.", "start_ms": 4000, "end_ms": 8000}, {"index": 2, "transcript": "But I know that every ending is a chance to start again.", "start_ms": 8000, "end_ms": 12800}, {"index": 3, "transcript": "So I will hold these memories close until the warm days come back.", "start_ms": 12800, "end_ms": 18000}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'songs'), 'Dancing in the Rain', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A2/songs/ex-songs-A2-004.mp3', 'Let us dance together in the rain tonight. I do not care if we get wet from head to toe. When you hold my hand and spin me round and round, I feel like the happiest person in the whole wide world.', 'A2', 2, 15, 42, '[{"index": 0, "transcript": "Let us dance together in the rain tonight.", "start_ms": 0, "end_ms": 3200}, {"index": 1, "transcript": "I do not care if we get wet from head to toe.", "start_ms": 3200, "end_ms": 8000}, {"index": 2, "transcript": "When you hold my hand and spin me round and round, I feel like the happiest person in the whole wide world.", "start_ms": 8000, "end_ms": 16800}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'songs'), 'Campfire Sing Along', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A2/songs/ex-songs-A2-005.mp3', 'Sit down beside me by the fire and tell me all the stories of the places you have been. The stars are shining bright above us and the night is young. So let us sing a song together underneath the open sky.', 'A2', 2, 15, 42, '[{"index": 0, "transcript": "Sit down beside me by the fire and tell me all the stories of the places you have been.", "start_ms": 0, "end_ms": 7600}, {"index": 1, "transcript": "The stars are shining bright above us and the night is young.", "start_ms": 7600, "end_ms": 12400}, {"index": 2, "transcript": "So let us sing a song together underneath the open sky.", "start_ms": 12400, "end_ms": 16800}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'songs'), 'Broken Wings Ballad', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B1/songs/ex-songs-B1-001.mp3', 'Sometimes the hardest thing and the right thing are the same, and you just have to keep moving forward even when the road is dark. I have been walking through this valley of shadows for so long now that I have almost forgotten what the sunlight feels like on my face. But somewhere deep inside my chest there is a tiny flame that refuses to go out, a stubborn spark of hope that whispers maybe tomorrow will be better than today.', 'B1', 3, 68, 81, '[{"index": 0, "transcript": "Sometimes the hardest thing and the right thing are the same, and you just have to keep moving forward even when the road is dark.", "start_ms": 0, "end_ms": 10000}, {"index": 1, "transcript": "I have been walking through this valley of shadows for so long now that I have almost forgotten what the sunlight feels like on my face.", "start_ms": 10000, "end_ms": 20400}, {"index": 2, "transcript": "But somewhere deep inside my chest there is a tiny flame that refuses to go out, a stubborn spark of hope that whispers maybe tomorrow will be better than today.", "start_ms": 20400, "end_ms": 32400}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'songs'), 'City Lights Anthem', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B1/songs/ex-songs-B1-002.mp3', 'The city never sleeps and neither do I tonight. A thousand windows glow like fireflies against the velvet sky. Every stranger passing by carries a universe inside their mind, stories that will never be told, dreams that will never find the light. But tonight we are alive and that is more than enough reason to raise our voices high and sing until the morning comes to chase away the dark.', 'B1', 3, 72, 70, '[{"index": 0, "transcript": "The city never sleeps and neither do I tonight.", "start_ms": 0, "end_ms": 3600}, {"index": 1, "transcript": "A thousand windows glow like fireflies against the velvet sky.", "start_ms": 3600, "end_ms": 7600}, {"index": 2, "transcript": "Every stranger passing by carries a universe inside their mind, stories that will never be told, dreams that will never find the light.", "start_ms": 7600, "end_ms": 16800}, {"index": 3, "transcript": "But tonight we are alive and that is more than enough reason to raise our voices high and sing until the morning comes to chase away the dark.", "start_ms": 16800, "end_ms": 28000}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'songs'), 'Heartbreak Recovery', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B1/songs/ex-songs-B1-003.mp3', 'You left without a warning on a cold November night and took a piece of me I thought I could not live without. For months I walked around like half a person, smiling on the outside while my world was falling apart within. But seasons change and people heal in ways they never thought possible. Now I stand here stronger than I ever was before, wearing my scars like armor and my pain like a crown.', 'B1', 3, 75, 76, '[{"index": 0, "transcript": "You left without a warning on a cold November night and took a piece of me I thought I could not live without.", "start_ms": 0, "end_ms": 9200}, {"index": 1, "transcript": "For months I walked around like half a person, smiling on the outside while my world was falling apart within.", "start_ms": 9200, "end_ms": 17200}, {"index": 2, "transcript": "But seasons change and people heal in ways they never thought possible.", "start_ms": 17200, "end_ms": 22000}, {"index": 3, "transcript": "Now I stand here stronger than I ever was before, wearing my scars like armor and my pain like a crown.", "start_ms": 22000, "end_ms": 30400}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'songs'), 'Ocean Waves Lullaby', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B1/songs/ex-songs-B1-004.mp3', 'Lay your head down on the pillow and let the ocean waves sing you to sleep tonight. The moon is hanging low above the water, painting silver ribbons on the tide. Everything that troubled you today can wait until tomorrow comes around. For now just close your eyes and let the rhythm of the sea carry you away to a place where worries cannot follow.', 'B1', 3, 70, 65, '[{"index": 0, "transcript": "Lay your head down on the pillow and let the ocean waves sing you to sleep tonight.", "start_ms": 0, "end_ms": 6800}, {"index": 1, "transcript": "The moon is hanging low above the water, painting silver ribbons on the tide.", "start_ms": 6800, "end_ms": 12400}, {"index": 2, "transcript": "Everything that troubled you today can wait until tomorrow comes around.", "start_ms": 12400, "end_ms": 16800}, {"index": 3, "transcript": "For now just close your eyes and let the rhythm of the sea carry you away to a place where worries cannot follow.", "start_ms": 16800, "end_ms": 26000}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'songs'), 'Revolution Anthem', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B1/songs/ex-songs-B1-005.mp3', 'They built their towers high upon the backs of those who had nothing left to lose, and called it progress while the people at the bottom struggled just to breathe. But every wall that has ever been built eventually comes tumbling down, and every voice that was silenced finds a way to make itself heard again. So raise your fists and raise your flags because tonight we take back what was always ours.', 'B1', 3, 73, 73, '[{"index": 0, "transcript": "They built their towers high upon the backs of those who had nothing left to lose, and called it progress while the people at the bottom struggled just to breathe.", "start_ms": 0, "end_ms": 12000}, {"index": 1, "transcript": "But every wall that has ever been built eventually comes tumbling down, and every voice that was silenced finds a way to make itself heard again.", "start_ms": 12000, "end_ms": 22400}, {"index": 2, "transcript": "So raise your fists and raise your flags because tonight we take back what was always ours.", "start_ms": 22400, "end_ms": 29200}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'songs'), 'Existential Rock Anthem', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B2/songs/ex-songs-B2-001.mp3', 'We were standing on the edge of something beautiful, not knowing whether to jump or to turn around and walk away from it all. The night sky stretched endlessly above us like a cathedral made of starlight, and for a single breathless moment the entire universe seemed to pause and hold its breath as if waiting for us to make a decision that would echo through eternity. I have replayed that moment ten thousand times inside my head, trying to pinpoint the exact instant when everything shifted from possibility to regret.', 'B2', 4, 27, 91, '[{"index": 0, "transcript": "We were standing on the edge of something beautiful, not knowing whether to jump or to turn around and walk away from it all.", "start_ms": 0, "end_ms": 9600}, {"index": 1, "transcript": "The night sky stretched endlessly above us like a cathedral made of starlight, and for a single breathless moment the entire universe seemed to pause and hold its breath as if waiting for us to make a decision that would echo through eternity.", "start_ms": 9600, "end_ms": 26800}, {"index": 2, "transcript": "I have replayed that moment ten thousand times inside my head, trying to pinpoint the exact instant when everything shifted from possibility to regret.", "start_ms": 26800, "end_ms": 36400}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'songs'), 'Midnight Confession Ballad', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B2/songs/ex-songs-B2-002.mp3', 'I have been carrying these words inside my chest like stones for longer than I care to remember, each one growing heavier with every sunset that passed without me finding the courage to speak them aloud. The world keeps spinning forward whether we are ready or not, and all these opportunities to be honest with the people we love slip through our fingers like water, impossible to hold and impossible to reclaim once they have disappeared into the relentless current of time.', 'B2', 4, 25, 82, '[{"index": 0, "transcript": "I have been carrying these words inside my chest like stones for longer than I care to remember, each one growing heavier with every sunset that passed without me finding the courage to speak them aloud.", "start_ms": 0, "end_ms": 14400}, {"index": 1, "transcript": "The world keeps spinning forward whether we are ready or not, and all these opportunities to be honest with the people we love slip through our fingers like water, impossible to hold and impossible to reclaim once they have disappeared into the relentless current of time.", "start_ms": 14400, "end_ms": 32800}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'songs'), 'Wanderer''s Folk Song', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B2/songs/ex-songs-B2-003.mp3', 'I left my hometown on a Tuesday morning with nothing but a guitar, a backpack full of notebooks, and a stubborn refusal to accept that the boundaries of my world had to be limited to the same streets I had walked since childhood. Every road I traveled introduced me to strangers who became brothers, to sunsets that redefined my understanding of beauty, and to hardships that stripped away the comfortable illusions I had been clinging to since the day I was old enough to be afraid.', 'B2', 4, 25, 86, '[{"index": 0, "transcript": "I left my hometown on a Tuesday morning with nothing but a guitar, a backpack full of notebooks, and a stubborn refusal to accept that the boundaries of my world had to be limited to the same streets I had walked since childhood.", "start_ms": 0, "end_ms": 17200}, {"index": 1, "transcript": "Every road I traveled introduced me to strangers who became brothers, to sunsets that redefined my understanding of beauty, and to hardships that stripped away the comfortable illusions I had been clinging to since the day I was old enough to be afraid.", "start_ms": 17200, "end_ms": 34400}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'songs'), 'Autumn Melancholy', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B2/songs/ex-songs-B2-004.mp3', 'There is a particular quality of sadness that only arrives with the first cold wind of autumn, when the trees begin their slow surrender and the world prepares itself for the long silence of winter. It is the kind of melancholy that settles into your bones like an old friend returning after a long absence, familiar and unwelcome in equal measure. Every falling leaf becomes a metaphor for the things we have lost and cannot recover, every shortened day a reminder that time moves in only one direction.', 'B2', 4, 28, 88, '[{"index": 0, "transcript": "There is a particular quality of sadness that only arrives with the first cold wind of autumn, when the trees begin their slow surrender and the world prepares itself for the long silence of winter.", "start_ms": 0, "end_ms": 14000}, {"index": 1, "transcript": "It is the kind of melancholy that settles into your bones like an old friend returning after a long absence, familiar and unwelcome in equal measure.", "start_ms": 14000, "end_ms": 24400}, {"index": 2, "transcript": "Every falling leaf becomes a metaphor for the things we have lost and cannot recover, every shortened day a reminder that time moves in only one direction.", "start_ms": 24400, "end_ms": 35200}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'songs'), 'Electric Dreams', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B2/songs/ex-songs-B2-005.mp3', 'We built a digital cathedral from binary code and fractured light, uploading our memories to servers that hum in the darkness of climate controlled rooms while outside the real world continues its messy, beautiful, chaotic existence without us. Somewhere between the first click and the millionth scroll, we traded genuine human connection for the comfortable numbness of curated feeds and algorithmic validation, convincing ourselves that a heart emoji from a stranger carries the same weight as an embrace.', 'B2', 4, 27, 78, '[{"index": 0, "transcript": "We built a digital cathedral from binary code and fractured light, uploading our memories to servers that hum in the darkness of climate controlled rooms while outside the real world continues its messy, beautiful, chaotic existence without us.", "start_ms": 0, "end_ms": 15200}, {"index": 1, "transcript": "Somewhere between the first click and the millionth scroll, we traded genuine human connection for the comfortable numbness of curated feeds and algorithmic validation, convincing ourselves that a heart emoji from a stranger carries the same weight as an embrace.", "start_ms": 15200, "end_ms": 31200}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'songs'), 'Ethereal Dream Sequence', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/C1/songs/ex-songs-C1-001.mp3', 'Beneath the weight of unspoken words and the silence that stretched between us like an ocean, I realized that some distances cannot be measured in miles but only in the things we failed to say when saying them might have altered the trajectory of two lives spiraling in opposite directions. The architecture of our shared history was built upon foundations of deliberate misunderstanding, each conversation a carefully choreographed dance of evasion in which we both conspired to avoid the one truth that would have either saved us or destroyed us completely, and looking back now through the distorting lens of accumulated years, I cannot determine which outcome we feared more.', 'C1', 5, 32, 110, '[{"index": 0, "transcript": "Beneath the weight of unspoken words and the silence that stretched between us like an ocean, I realized that some distances cannot be measured in miles but only in the things we failed to say when saying them might have altered the trajectory of two lives spiraling in opposite directions.", "start_ms": 0, "end_ms": 20000}, {"index": 1, "transcript": "The architecture of our shared history was built upon foundations of deliberate misunderstanding, each conversation a carefully choreographed dance of evasion in which we both conspired to avoid the one truth that would have either saved us or destroyed us completely, and looking back now through the distorting lens of accumulated years, I cannot determine which outcome we feared more.", "start_ms": 20000, "end_ms": 44000}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'songs'), 'Protest Hymn for Tomorrow', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/C1/songs/ex-songs-C1-002.mp3', 'They paved the meadows where our grandmothers gathered wildflowers and erected monuments to a progress that tastes like ash on the tongues of those who remember what the world looked like before efficiency became our highest deity and productivity the only prayer we were permitted to utter. The rivers that once sang their way through ancient forests now carry the chemical whispers of a civilization that has confused consumption with purpose and convenience with happiness, and somewhere in the vast machinery of modern life the fundamental question of what it means to live well has been quietly replaced by the far simpler question of how to live fast.', 'C1', 5, 32, 108, '[{"index": 0, "transcript": "They paved the meadows where our grandmothers gathered wildflowers and erected monuments to a progress that tastes like ash on the tongues of those who remember what the world looked like before efficiency became our highest deity and productivity the only prayer we were permitted to utter.", "start_ms": 0, "end_ms": 18800}, {"index": 1, "transcript": "The rivers that once sang their way through ancient forests now carry the chemical whispers of a civilization that has confused consumption with purpose and convenience with happiness, and somewhere in the vast machinery of modern life the fundamental question of what it means to live well has been quietly replaced by the far simpler question of how to live fast.", "start_ms": 18800, "end_ms": 43200}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'songs'), 'Cosmic Love Letter', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/C1/songs/ex-songs-C1-003.mp3', 'If the physicists are correct and every atom in our bodies was forged in the nuclear furnace of a dying star billions of years before the Earth itself coalesced from cosmic debris, then the love I feel for you is not merely a biochemical reaction engineered by evolution to promote pair bonding and reproductive success. It is something far more ancient and mysterious, a gravitational force that has been pulling matter toward matter since the first microsecond after the universe exploded into existence from a singularity of infinite density and infinite possibility. Consider the staggering improbability of our meeting, the countless random mutations and extinction events that had to occur in precisely the right sequence for two specific arrangements of stardust to find themselves sitting across from each other at a coffee shop on a rainy Tuesday afternoon.', 'C1', 5, 43, 138, '[{"index": 0, "transcript": "If the physicists are correct and every atom in our bodies was forged in the nuclear furnace of a dying star billions of years before the Earth itself coalesced from cosmic debris, then the love I feel for you is not merely a biochemical reaction engineered by evolution to promote pair bonding and reproductive success.", "start_ms": 0, "end_ms": 22000}, {"index": 1, "transcript": "It is something far more ancient and mysterious, a gravitational force that has been pulling matter toward matter since the first microsecond after the universe exploded into existence from a singularity of infinite density and infinite possibility.", "start_ms": 22000, "end_ms": 36800}, {"index": 2, "transcript": "Consider the staggering improbability of our meeting, the countless random mutations and extinction events that had to occur in precisely the right sequence for two specific arrangements of stardust to find themselves sitting across from each other at a coffee shop on a rainy Tuesday afternoon.", "start_ms": 36800, "end_ms": 55200}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'songs'), 'Urban Decay Elegy', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/C1/songs/ex-songs-C1-004.mp3', 'In the abandoned factories where my father spent thirty years transforming raw materials into the infrastructure of American prosperity, wildflowers now push through cracks in the concrete floor like stubborn testament to the regenerative capacity of nature in the face of industrial decay. The machinery that once thundered through three shifts stands frozen in rust and silence, each corroded gear and broken conveyor belt a fossilized record of an economic transformation that left entire communities stranded between the wreckage of what was promised and the empty horizon of what replaced it. I walk these corridors not out of nostalgia but because understanding where we have been is the only reliable method for navigating where we are going.', 'C1', 5, 37, 117, '[{"index": 0, "transcript": "In the abandoned factories where my father spent thirty years transforming raw materials into the infrastructure of American prosperity, wildflowers now push through cracks in the concrete floor like stubborn testament to the regenerative capacity of nature in the face of industrial decay.", "start_ms": 0, "end_ms": 17200}, {"index": 1, "transcript": "The machinery that once thundered through three shifts stands frozen in rust and silence, each corroded gear and broken conveyor belt a fossilized record of an economic transformation that left entire communities stranded between the wreckage of what was promised and the empty horizon of what replaced it.", "start_ms": 17200, "end_ms": 36400}, {"index": 2, "transcript": "I walk these corridors not out of nostalgia but because understanding where we have been is the only reliable method for navigating where we are going.", "start_ms": 36400, "end_ms": 46800}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'songs'), 'Final Song Before Dawn', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/C1/songs/ex-songs-C1-005.mp3', 'The last note hangs in the air like a question that nobody present has the courage or the wisdom to answer, and in the silence that follows I can hear the collective heartbeat of every person in this room synchronizing into a single rhythm that transcends the artificial boundaries of language and culture and ideology that we spend our waking hours so diligently constructing between ourselves. Music has always possessed this subversive power, this ability to bypass the rational mind''s elaborate defense mechanisms and speak directly to the part of us that existed before words, before logic, before the first human being looked at another human being and decided that difference was something to be feared rather than celebrated.', 'C1', 5, 35, 119, '[{"index": 0, "transcript": "The last note hangs in the air like a question that nobody present has the courage or the wisdom to answer, and in the silence that follows I can hear the collective heartbeat of every person in this room synchronizing into a single rhythm that transcends the artificial boundaries of language and culture and ideology that we spend our waking hours so diligently constructing between ourselves.", "start_ms": 0, "end_ms": 26400}, {"index": 1, "transcript": "Music has always possessed this subversive power, this ability to bypass the rational mind''s elaborate defense mechanisms and speak directly to the part of us that existed before words, before logic, before the first human being looked at another human being and decided that difference was something to be feared rather than celebrated.", "start_ms": 26400, "end_ms": 47600}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'ted-talks'), 'TED: Welcome and Thank You', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A1/ted-talks/ex-ted-A1-001.mp3', 'Thank you. I am very happy to be here today. I want to talk about something important.', 'A1', 1, 10, 17, '[{"index": 0, "transcript": "Thank you.", "start_ms": 0, "end_ms": 1500}, {"index": 1, "transcript": "I am very happy to be here today.", "start_ms": 1500, "end_ms": 4700}, {"index": 2, "transcript": "I want to talk about something important.", "start_ms": 4700, "end_ms": 7500}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'ted-talks'), 'TED: Be Kind', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A1/ted-talks/ex-ted-A1-002.mp3', 'Be kind to people. A small act of kindness can change someone''s whole day. Smile more.', 'A1', 1, 10, 16, '[{"index": 0, "transcript": "Be kind to people.", "start_ms": 0, "end_ms": 1600}, {"index": 1, "transcript": "A small act of kindness can change someone''s whole day.", "start_ms": 1600, "end_ms": 5600}, {"index": 2, "transcript": "Smile more.", "start_ms": 5600, "end_ms": 7100}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'ted-talks'), 'TED: Never Give Up', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A1/ted-talks/ex-ted-A1-003.mp3', 'Do not give up. When things are hard, keep trying. You can do it if you believe.', 'A1', 1, 10, 17, '[{"index": 0, "transcript": "Do not give up.", "start_ms": 0, "end_ms": 1600}, {"index": 1, "transcript": "When things are hard, keep trying.", "start_ms": 1600, "end_ms": 4000}, {"index": 2, "transcript": "You can do it if you believe.", "start_ms": 4000, "end_ms": 6800}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'ted-talks'), 'TED: Read Every Day', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A1/ted-talks/ex-ted-A1-004.mp3', 'Reading is good for your brain. Try to read every day. Even ten minutes helps a lot.', 'A1', 1, 9, 17, '[{"index": 0, "transcript": "Reading is good for your brain.", "start_ms": 0, "end_ms": 2400}, {"index": 1, "transcript": "Try to read every day.", "start_ms": 2400, "end_ms": 4400}, {"index": 2, "transcript": "Even ten minutes helps a lot.", "start_ms": 4400, "end_ms": 6800}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'ted-talks'), 'TED: Water Is Life', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A1/ted-talks/ex-ted-A1-005.mp3', 'Water is very important. We need clean water to live. Many people do not have enough water.', 'A1', 1, 11, 17, '[{"index": 0, "transcript": "Water is very important.", "start_ms": 0, "end_ms": 1600}, {"index": 1, "transcript": "We need clean water to live.", "start_ms": 1600, "end_ms": 4000}, {"index": 2, "transcript": "Many people do not have enough water.", "start_ms": 4000, "end_ms": 6800}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'ted-talks'), 'TED: The Power of Saying Sorry', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A2/ted-talks/ex-ted-A2-001.mp3', 'Every single person in this room has made a mistake they wish they could take back. The interesting thing about saying sorry is that it does not make you weak. In fact, it takes a lot of courage to admit when you are wrong and to try to make things better.', 'A2', 2, 21, 51, '[{"index": 0, "transcript": "Every single person in this room has made a mistake they wish they could take back.", "start_ms": 0, "end_ms": 6400}, {"index": 1, "transcript": "The interesting thing about saying sorry is that it does not make you weak.", "start_ms": 6400, "end_ms": 12000}, {"index": 2, "transcript": "In fact, it takes a lot of courage to admit when you are wrong and to try to make things better.", "start_ms": 12000, "end_ms": 20400}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'ted-talks'), 'TED: Why We Sleep', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A2/ted-talks/ex-ted-A2-002.mp3', 'Most adults need about eight hours of sleep every night, but many people only get six or less. When we do not sleep enough, our memory gets worse and we feel tired all day. Sleep is not a luxury. It is something our body truly needs to stay healthy and strong.', 'A2', 2, 19, 51, '[{"index": 0, "transcript": "Most adults need about eight hours of sleep every night, but many people only get six or less.", "start_ms": 0, "end_ms": 7200}, {"index": 1, "transcript": "When we do not sleep enough, our memory gets worse and we feel tired all day.", "start_ms": 7200, "end_ms": 13600}, {"index": 2, "transcript": "Sleep is not a luxury.", "start_ms": 13600, "end_ms": 15600}, {"index": 3, "transcript": "It is something our body truly needs to stay healthy and strong.", "start_ms": 15600, "end_ms": 20400}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'ted-talks'), 'TED: Learning From Failure', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A2/ted-talks/ex-ted-A2-003.mp3', 'I failed many times before I finally succeeded. Each failure taught me something new and helped me grow as a person. If you are afraid of failing, you will never try new things. The key is to see failure not as the end but as the beginning of something better.', 'A2', 2, 23, 50, '[{"index": 0, "transcript": "I failed many times before I finally succeeded.", "start_ms": 0, "end_ms": 3200}, {"index": 1, "transcript": "Each failure taught me something new and helped me grow as a person.", "start_ms": 3200, "end_ms": 8400}, {"index": 2, "transcript": "If you are afraid of failing, you will never try new things.", "start_ms": 8400, "end_ms": 13200}, {"index": 3, "transcript": "The key is to see failure not as the end but as the beginning of something better.", "start_ms": 13200, "end_ms": 20000}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'ted-talks'), 'TED: Small Habits Big Change', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A2/ted-talks/ex-ted-A2-004.mp3', 'You do not need to change everything at once. Start with one small habit, like drinking a glass of water every morning or walking for ten minutes after lunch. Over time, these small changes add up and before you know it, your whole life is different.', 'A2', 2, 17, 46, '[{"index": 0, "transcript": "You do not need to change everything at once.", "start_ms": 0, "end_ms": 3600}, {"index": 1, "transcript": "Start with one small habit, like drinking a glass of water every morning or walking for ten minutes after lunch.", "start_ms": 3600, "end_ms": 11600}, {"index": 2, "transcript": "Over time, these small changes add up and before you know it, your whole life is different.", "start_ms": 11600, "end_ms": 18400}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'ted-talks'), 'TED: Why Music Matters', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A2/ted-talks/ex-ted-A2-005.mp3', 'Music connects people in a way that words alone cannot. When you listen to a song in a language you do not understand, you can still feel the emotion behind it. That is the power of music. It crosses borders and brings people together from all over the world.', 'A2', 2, 22, 49, '[{"index": 0, "transcript": "Music connects people in a way that words alone cannot.", "start_ms": 0, "end_ms": 4000}, {"index": 1, "transcript": "When you listen to a song in a language you do not understand, you can still feel the emotion behind it.", "start_ms": 4000, "end_ms": 12400}, {"index": 2, "transcript": "That is the power of music.", "start_ms": 12400, "end_ms": 14800}, {"index": 3, "transcript": "It crosses borders and brings people together from all over the world.", "start_ms": 14800, "end_ms": 19600}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'ted-talks'), 'TED: The Science of Happiness', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B1/ted-talks/ex-ted-B1-001.mp3', 'Connection is why we are here. It is what gives purpose and meaning to our lives and it starts with being brave enough to be honest about who we are and what we need. Researchers have found that the single most reliable predictor of long term happiness is not wealth or professional achievement but rather the quality of our relationships with the people around us. Those who invest time and energy in building genuine connections report significantly higher levels of life satisfaction.', 'B1', 3, 70, 82, '[{"index": 0, "transcript": "Connection is why we are here.", "start_ms": 0, "end_ms": 2400}, {"index": 1, "transcript": "It is what gives purpose and meaning to our lives and it starts with being brave enough to be honest about who we are and what we need.", "start_ms": 2400, "end_ms": 13600}, {"index": 2, "transcript": "Researchers have found that the single most reliable predictor of long term happiness is not wealth or professional achievement but rather the quality of our relationships with the people around us.", "start_ms": 13600, "end_ms": 26000}, {"index": 3, "transcript": "Those who invest time and energy in building genuine connections report significantly higher levels of life satisfaction.", "start_ms": 26000, "end_ms": 32800}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'ted-talks'), 'TED: The Habit Loop', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B1/ted-talks/ex-ted-B1-002.mp3', 'The secret to building a good habit is to start so small that it feels almost impossible to fail. If you want to exercise more, begin by doing just two push-ups a day. If you want to read more, start with a single page before bed. The reason this works is that our brains are wired to seek consistency and once a behavior becomes automatic through repetition, scaling it up requires remarkably little additional willpower.', 'B1', 3, 72, 75, '[{"index": 0, "transcript": "The secret to building a good habit is to start so small that it feels almost impossible to fail.", "start_ms": 0, "end_ms": 7600}, {"index": 1, "transcript": "If you want to exercise more, begin by doing just two push-ups a day.", "start_ms": 7600, "end_ms": 13200}, {"index": 2, "transcript": "If you want to read more, start with a single page before bed.", "start_ms": 13200, "end_ms": 18400}, {"index": 3, "transcript": "The reason this works is that our brains are wired to seek consistency and once a behavior becomes automatic through repetition, scaling it up requires remarkably little additional willpower.", "start_ms": 18400, "end_ms": 30000}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'ted-talks'), 'TED: Digital Minimalism', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B1/ted-talks/ex-ted-B1-003.mp3', 'The average person checks their phone approximately ninety six times per day, which amounts to roughly once every ten minutes during waking hours. Each notification triggers a small dopamine release in our brains, creating a feedback loop that keeps us reaching for our devices even when we have no specific reason to do so. The solution is not necessarily to abandon technology altogether but rather to develop a more intentional relationship with our digital tools.', 'B1', 3, 75, 75, '[{"index": 0, "transcript": "The average person checks their phone approximately ninety six times per day, which amounts to roughly once every ten minutes during waking hours.", "start_ms": 0, "end_ms": 9200}, {"index": 1, "transcript": "Each notification triggers a small dopamine release in our brains, creating a feedback loop that keeps us reaching for our devices even when we have no specific reason to do so.", "start_ms": 9200, "end_ms": 21600}, {"index": 2, "transcript": "The solution is not necessarily to abandon technology altogether but rather to develop a more intentional relationship with our digital tools.", "start_ms": 21600, "end_ms": 30000}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'ted-talks'), 'TED: Creative Confidence', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B1/ted-talks/ex-ted-B1-004.mp3', 'When I ask a room full of adults to draw a picture, most of them immediately apologize and say they are not creative. But when I ask the same question to a group of five year old children, every single hand shoots up with enthusiasm. Somewhere between childhood and adulthood, most people convince themselves that creativity is a talent reserved for a special few rather than a fundamental human capability that can be developed through practice.', 'B1', 3, 78, 76, '[{"index": 0, "transcript": "When I ask a room full of adults to draw a picture, most of them immediately apologize and say they are not creative.", "start_ms": 0, "end_ms": 9200}, {"index": 1, "transcript": "But when I ask the same question to a group of five year old children, every single hand shoots up with enthusiasm.", "start_ms": 9200, "end_ms": 18000}, {"index": 2, "transcript": "Somewhere between childhood and adulthood, most people convince themselves that creativity is a talent reserved for a special few rather than a fundamental human capability that can be developed through practice.", "start_ms": 18000, "end_ms": 30400}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'ted-talks'), 'TED: The Future of Food', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B1/ted-talks/ex-ted-B1-005.mp3', 'By the year twenty fifty, the global population is expected to reach nearly ten billion people, which means we will need to produce approximately seventy percent more food than we do today. The challenge is not simply one of quantity but of sustainability, because the agricultural methods that have fueled population growth over the past century are simultaneously responsible for deforestation, water pollution, and a significant portion of greenhouse gas emissions.', 'B1', 3, 80, 71, '[{"index": 0, "transcript": "By the year twenty fifty, the global population is expected to reach nearly ten billion people, which means we will need to produce approximately seventy percent more food than we do today.", "start_ms": 0, "end_ms": 12800}, {"index": 1, "transcript": "The challenge is not simply one of quantity but of sustainability, because the agricultural methods that have fueled population growth over the past century are simultaneously responsible for deforestation, water pollution, and a significant portion of greenhouse gas emissions.", "start_ms": 12800, "end_ms": 28400}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'ted-talks'), 'TED: Cognitive Biases', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B2/ted-talks/ex-ted-B2-001.mp3', 'Research has consistently shown that our brains are wired to respond to stories far more powerfully than to statistics or abstract data alone. This phenomenon, known as the narrative bias, explains why a single compelling personal anecdote often carries more persuasive weight than a mountain of carefully collected evidence. Understanding this tendency does not make us immune to it, but awareness is the first step toward making more rational decisions.', 'B2', 4, 31, 70, '[{"index": 0, "transcript": "Research has consistently shown that our brains are wired to respond to stories far more powerfully than to statistics or abstract data alone.", "start_ms": 0, "end_ms": 9200}, {"index": 1, "transcript": "This phenomenon, known as the narrative bias, explains why a single compelling personal anecdote often carries more persuasive weight than a mountain of carefully collected evidence.", "start_ms": 9200, "end_ms": 19600}, {"index": 2, "transcript": "Understanding this tendency does not make us immune to it, but awareness is the first step toward making more rational decisions.", "start_ms": 19600, "end_ms": 28000}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'ted-talks'), 'TED: Reimagining Education', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B2/ted-talks/ex-ted-B2-002.mp3', 'If we continue to evaluate intelligence solely through the narrow lens of standardized testing, we risk overlooking the creative and critical thinking skills that are arguably more essential in navigating the complexities of the modern world. The educational system we inherited was designed for an industrial economy that valued compliance and memorization above all else. Today we live in a knowledge economy that demands adaptability, collaboration, and the ability to synthesize information from multiple sources.', 'B2', 4, 27, 75, '[{"index": 0, "transcript": "If we continue to evaluate intelligence solely through the narrow lens of standardized testing, we risk overlooking the creative and critical thinking skills that are arguably more essential in navigating the complexities of the modern world.", "start_ms": 0, "end_ms": 14400}, {"index": 1, "transcript": "The educational system we inherited was designed for an industrial economy that valued compliance and memorization above all else.", "start_ms": 14400, "end_ms": 22000}, {"index": 2, "transcript": "Today we live in a knowledge economy that demands adaptability, collaboration, and the ability to synthesize information from multiple sources.", "start_ms": 22000, "end_ms": 30000}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'ted-talks'), 'TED: The Paradox of Choice', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B2/ted-talks/ex-ted-B2-003.mp3', 'We live in a society that equates freedom with the abundance of options available to us, operating under the assumption that more choices necessarily lead to better outcomes and greater satisfaction. However, psychological research conducted over the past two decades presents a far more nuanced picture. When confronted with an excessive number of alternatives, people frequently experience what researchers call decision paralysis, a state of anxiety and indecision that often results in either no choice at all or significantly reduced satisfaction.', 'B2', 4, 36, 81, '[{"index": 0, "transcript": "We live in a society that equates freedom with the abundance of options available to us, operating under the assumption that more choices necessarily lead to better outcomes and greater satisfaction.", "start_ms": 0, "end_ms": 12400}, {"index": 1, "transcript": "However, psychological research conducted over the past two decades presents a far more nuanced picture.", "start_ms": 12400, "end_ms": 18400}, {"index": 2, "transcript": "When confronted with an excessive number of alternatives, people frequently experience what researchers call decision paralysis, a state of anxiety and indecision that often results in either no choice at all or significantly reduced satisfaction.", "start_ms": 18400, "end_ms": 32400}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'ted-talks'), 'TED: Emotional Intelligence', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B2/ted-talks/ex-ted-B2-004.mp3', 'For decades, the concept of intelligence was synonymous with cognitive ability, measured primarily through standardized IQ tests that assessed logical reasoning, mathematical aptitude, and linguistic facility. What these assessments consistently failed to capture was the equally vital dimension of emotional intelligence, the capacity to recognize and manage one''s own emotional states while simultaneously perceiving and responding appropriately to the emotions of others. Contemporary research has demonstrated that emotional intelligence is a significantly more reliable predictor of professional success.', 'B2', 4, 32, 78, '[{"index": 0, "transcript": "For decades, the concept of intelligence was synonymous with cognitive ability, measured primarily through standardized IQ tests that assessed logical reasoning, mathematical aptitude, and linguistic facility.", "start_ms": 0, "end_ms": 10400}, {"index": 1, "transcript": "What these assessments consistently failed to capture was the equally vital dimension of emotional intelligence, the capacity to recognize and manage one''s own emotional states while simultaneously perceiving and responding appropriately to the emotions of others.", "start_ms": 10400, "end_ms": 24800}, {"index": 2, "transcript": "Contemporary research has demonstrated that emotional intelligence is a significantly more reliable predictor of professional success.", "start_ms": 24800, "end_ms": 31200}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'ted-talks'), 'TED: The Microbiome Revolution', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B2/ted-talks/ex-ted-B2-005.mp3', 'Inside your body right now there are approximately thirty eight trillion microorganisms, a number that slightly exceeds the total count of human cells you possess. This vast ecosystem of bacteria, fungi, and viruses, collectively known as the microbiome, influences everything from your immune system response and metabolic rate to your mood and cognitive function. Recent discoveries have revealed that the composition of your gut microbiome may play a decisive role in conditions ranging from obesity and diabetes to depression and anxiety.', 'B2', 4, 37, 81, '[{"index": 0, "transcript": "Inside your body right now there are approximately thirty eight trillion microorganisms, a number that slightly exceeds the total count of human cells you possess.", "start_ms": 0, "end_ms": 10000}, {"index": 1, "transcript": "This vast ecosystem of bacteria, fungi, and viruses, collectively known as the microbiome, influences everything from your immune system response and metabolic rate to your mood and cognitive function.", "start_ms": 10000, "end_ms": 21600}, {"index": 2, "transcript": "Recent discoveries have revealed that the composition of your gut microbiome may play a decisive role in conditions ranging from obesity and diabetes to depression and anxiety.", "start_ms": 21600, "end_ms": 32400}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'ted-talks'), 'TED: The Architecture of Belief', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/C1/ted-talks/ex-ted-C1-001.mp3', 'The most dangerous ideas in human history have never been the ones that were obviously wrong. They were the ones that contained just enough truth to be plausible while simultaneously embedding within their logical framework assumptions so fundamental that questioning them felt not merely intellectually challenging but existentially threatening. Consider how the geocentric model of the universe persisted for over a millennium not because the evidence was overwhelming but because the alternative, that humanity occupied no privileged position in the cosmos, was psychologically intolerable to a civilization that had constructed its entire moral and social architecture upon the premise of human centrality.', 'C1', 5, 42, 102, '[{"index": 0, "transcript": "The most dangerous ideas in human history have never been the ones that were obviously wrong.", "start_ms": 0, "end_ms": 6400}, {"index": 1, "transcript": "They were the ones that contained just enough truth to be plausible while simultaneously embedding within their logical framework assumptions so fundamental that questioning them felt not merely intellectually challenging but existentially threatening.", "start_ms": 6400, "end_ms": 19600}, {"index": 2, "transcript": "Consider how the geocentric model of the universe persisted for over a millennium not because the evidence was overwhelming but because the alternative, that humanity occupied no privileged position in the cosmos, was psychologically intolerable to a civilization that had constructed its entire moral and social architecture upon the premise of human centrality.", "start_ms": 19600, "end_ms": 40800}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'ted-talks'), 'TED: Language and Thought', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/C1/ted-talks/ex-ted-C1-002.mp3', 'The relationship between language and thought represents one of the most fascinating and contentious debates in cognitive science, touching upon fundamental questions about the nature of human consciousness and the degree to which our perception of reality is constructed rather than passively received. The Sapir-Whorf hypothesis, in its strongest formulation, suggests that the language we speak does not merely describe our experience of the world but actively shapes it, constraining the categories of thought available to us and rendering certain concepts literally unthinkable for speakers of languages that lack the appropriate lexical or grammatical resources.', 'C1', 5, 29, 95, '[{"index": 0, "transcript": "The relationship between language and thought represents one of the most fascinating and contentious debates in cognitive science, touching upon fundamental questions about the nature of human consciousness and the degree to which our perception of reality is constructed rather than passively received.", "start_ms": 0, "end_ms": 17200}, {"index": 1, "transcript": "The Sapir-Whorf hypothesis, in its strongest formulation, suggests that the language we speak does not merely describe our experience of the world but actively shapes it, constraining the categories of thought available to us and rendering certain concepts literally unthinkable for speakers of languages that lack the appropriate lexical or grammatical resources.", "start_ms": 17200, "end_ms": 38000}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'ted-talks'), 'TED: The Ethics of AI', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/C1/ted-talks/ex-ted-C1-003.mp3', 'As artificial intelligence systems become increasingly integrated into decision-making processes across healthcare, finance, and criminal justice, the question of algorithmic accountability and transparency has emerged as one of the most pressing ethical dilemmas of our generation. The fundamental challenge is not technical but philosophical: when an autonomous system makes a decision that causes harm, whether it be a diagnostic algorithm that misidentifies a malignant tumor or a predictive policing system that disproportionately targets minority communities, the traditional frameworks of moral responsibility that have governed human societies for millennia prove woefully inadequate.', 'C1', 5, 41, 91, '[{"index": 0, "transcript": "As artificial intelligence systems become increasingly integrated into decision-making processes across healthcare, finance, and criminal justice, the question of algorithmic accountability and transparency has emerged as one of the most pressing ethical dilemmas of our generation.", "start_ms": 0, "end_ms": 14400}, {"index": 1, "transcript": "The fundamental challenge is not technical but philosophical: when an autonomous system makes a decision that causes harm, whether it be a diagnostic algorithm that misidentifies a malignant tumor or a predictive policing system that disproportionately targets minority communities, the traditional frameworks of moral responsibility that have governed human societies for millennia prove woefully inadequate.", "start_ms": 14400, "end_ms": 36400}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'ted-talks'), 'TED: Consciousness and the Hard Problem', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/C1/ted-talks/ex-ted-C1-004.mp3', 'The hard problem of consciousness, as articulated by philosopher David Chalmers in nineteen ninety five, asks a deceptively simple question that has humbled some of the greatest minds in neuroscience and philosophy: why does subjective experience exist at all? We can map every neural pathway in the brain, identify the precise electrochemical processes that correspond to specific sensory inputs, and construct increasingly sophisticated computational models of cognitive function, yet none of this brings us any closer to explaining why there is something it is like to see the color red or taste chocolate or feel the warmth of another person''s hand.', 'C1', 5, 30, 101, '[{"index": 0, "transcript": "The hard problem of consciousness, as articulated by philosopher David Chalmers in nineteen ninety five, asks a deceptively simple question that has humbled some of the greatest minds in neuroscience and philosophy: why does subjective experience exist at all?", "start_ms": 0, "end_ms": 15600}, {"index": 1, "transcript": "We can map every neural pathway in the brain, identify the precise electrochemical processes that correspond to specific sensory inputs, and construct increasingly sophisticated computational models of cognitive function, yet none of this brings us any closer to explaining why there is something it is like to see the color red or taste chocolate or feel the warmth of another person''s hand.", "start_ms": 15600, "end_ms": 40400}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'ted-talks'), 'TED: Inequality and the Social Contract', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/C1/ted-talks/ex-ted-C1-005.mp3', 'The social contract that has undergirded democratic societies since the Enlightenment rests upon an implicit bargain between citizens and the state: individuals surrender certain natural freedoms in exchange for collective security, institutional justice, and the opportunity to participate meaningfully in economic life. For the better part of two centuries, this arrangement maintained sufficient legitimacy to sustain social cohesion even during periods of significant economic disruption, because the underlying trajectory pointed broadly toward expanding prosperity and widening access to the levers of political and economic power.', 'C1', 5, 38, 85, '[{"index": 0, "transcript": "The social contract that has undergirded democratic societies since the Enlightenment rests upon an implicit bargain between citizens and the state: individuals surrender certain natural freedoms in exchange for collective security, institutional justice, and the opportunity to participate meaningfully in economic life.", "start_ms": 0, "end_ms": 16800}, {"index": 1, "transcript": "For the better part of two centuries, this arrangement maintained sufficient legitimacy to sustain social cohesion even during periods of significant economic disruption, because the underlying trajectory pointed broadly toward expanding prosperity and widening access to the levers of political and economic power.", "start_ms": 16800, "end_ms": 34000}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'toeic'), 'TOEIC: Office Directions', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A1/toeic/ex-toeic-A1-001.mp3', 'The meeting room is on the second floor. Turn left after the elevator.', 'A1', 1, 7, 13, '[{"index": 0, "transcript": "The meeting room is on the second floor.", "start_ms": 0, "end_ms": 3200}, {"index": 1, "transcript": "Turn left after the elevator.", "start_ms": 3200, "end_ms": 5200}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'toeic'), 'TOEIC: Phone Message', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A1/toeic/ex-toeic-A1-002.mp3', 'Hello, this is Mr. Park. Please call me back at five five five, one two three four.', 'A1', 1, 9, 17, '[{"index": 0, "transcript": "Hello, this is Mr.", "start_ms": 0, "end_ms": 1600}, {"index": 1, "transcript": "Park.", "start_ms": 1600, "end_ms": 3100}, {"index": 2, "transcript": "Please call me back at five five five, one two three four.", "start_ms": 3100, "end_ms": 7900}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'toeic'), 'TOEIC: Lunch Break', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A1/toeic/ex-toeic-A1-003.mp3', 'The cafeteria is open from twelve to one. Today they have soup and sandwiches.', 'A1', 1, 8, 14, '[{"index": 0, "transcript": "The cafeteria is open from twelve to one.", "start_ms": 0, "end_ms": 3200}, {"index": 1, "transcript": "Today they have soup and sandwiches.", "start_ms": 3200, "end_ms": 5600}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'toeic'), 'TOEIC: Office Supply Request', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A1/toeic/ex-toeic-A1-004.mp3', 'We need more paper for the printer. Can you order some today, please?', 'A1', 1, 7, 13, '[{"index": 0, "transcript": "We need more paper for the printer.", "start_ms": 0, "end_ms": 2800}, {"index": 1, "transcript": "Can you order some today, please?", "start_ms": 2800, "end_ms": 5200}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'toeic'), 'TOEIC: Welcome New Employee', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A1/toeic/ex-toeic-A1-005.mp3', 'Welcome to the company. Your desk is next to the window. Here is your computer.', 'A1', 1, 9, 15, '[{"index": 0, "transcript": "Welcome to the company.", "start_ms": 0, "end_ms": 1600}, {"index": 1, "transcript": "Your desk is next to the window.", "start_ms": 1600, "end_ms": 4400}, {"index": 2, "transcript": "Here is your computer.", "start_ms": 4400, "end_ms": 6000}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'toeic'), 'TOEIC: Meeting Reschedule', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A2/toeic/ex-toeic-A2-001.mp3', 'The meeting has been moved to three o''clock this afternoon in room five. All team members should be there on time. Please bring your project reports and be ready to present your progress to the manager.', 'A2', 2, 14, 36, '[{"index": 0, "transcript": "The meeting has been moved to three o''clock this afternoon in room five.", "start_ms": 0, "end_ms": 5200}, {"index": 1, "transcript": "All team members should be there on time.", "start_ms": 5200, "end_ms": 8400}, {"index": 2, "transcript": "Please bring your project reports and be ready to present your progress to the manager.", "start_ms": 8400, "end_ms": 14400}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'toeic'), 'TOEIC: Job Interview Prep', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A2/toeic/ex-toeic-A2-002.mp3', 'Your interview is scheduled for next Tuesday at ten in the morning. Please arrive fifteen minutes early and bring two copies of your resume. You will meet with the hiring manager first and then the department head.', 'A2', 2, 14, 37, '[{"index": 0, "transcript": "Your interview is scheduled for next Tuesday at ten in the morning.", "start_ms": 0, "end_ms": 4800}, {"index": 1, "transcript": "Please arrive fifteen minutes early and bring two copies of your resume.", "start_ms": 4800, "end_ms": 9600}, {"index": 2, "transcript": "You will meet with the hiring manager first and then the department head.", "start_ms": 9600, "end_ms": 14800}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'toeic'), 'TOEIC: Travel Booking', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A2/toeic/ex-toeic-A2-003.mp3', 'I need to book a flight to Singapore for next Monday. The conference starts at nine in the morning, so I should arrive on Sunday evening. Can you also reserve a hotel room near the convention center for three nights?', 'A2', 2, 15, 40, '[{"index": 0, "transcript": "I need to book a flight to Singapore for next Monday.", "start_ms": 0, "end_ms": 4400}, {"index": 1, "transcript": "The conference starts at nine in the morning, so I should arrive on Sunday evening.", "start_ms": 4400, "end_ms": 10400}, {"index": 2, "transcript": "Can you also reserve a hotel room near the convention center for three nights?", "start_ms": 10400, "end_ms": 16000}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'toeic'), 'TOEIC: Office Announcement', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A2/toeic/ex-toeic-A2-004.mp3', 'Attention all staff. The parking lot will be closed for repairs this weekend. Please use the parking garage on Oak Street instead. Regular parking will be available again starting Monday morning.', 'A2', 2, 15, 31, '[{"index": 0, "transcript": "Attention all staff.", "start_ms": 0, "end_ms": 1500}, {"index": 1, "transcript": "The parking lot will be closed for repairs this weekend.", "start_ms": 1500, "end_ms": 5500}, {"index": 2, "transcript": "Please use the parking garage on Oak Street instead.", "start_ms": 5500, "end_ms": 9100}, {"index": 3, "transcript": "Regular parking will be available again starting Monday morning.", "start_ms": 9100, "end_ms": 12700}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'toeic'), 'TOEIC: Customer Service Call', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A2/toeic/ex-toeic-A2-005.mp3', 'Thank you for calling tech support. My name is Lisa and I will be helping you today. Could you please tell me your account number and describe the problem you are experiencing with your computer?', 'A2', 2, 13, 35, '[{"index": 0, "transcript": "Thank you for calling tech support.", "start_ms": 0, "end_ms": 2400}, {"index": 1, "transcript": "My name is Lisa and I will be helping you today.", "start_ms": 2400, "end_ms": 6800}, {"index": 2, "transcript": "Could you please tell me your account number and describe the problem you are experiencing with your computer?", "start_ms": 6800, "end_ms": 14000}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'toeic'), 'TOEIC: Budget Proposal Discussion', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B1/toeic/ex-toeic-B1-001.mp3', 'We need to finalize the budget proposal before the end of this week so that management can review it on Monday. I have been looking at the numbers from last quarter and there are a few areas where we can cut costs without affecting the quality of our services. Marketing expenses have increased by twenty percent compared to the previous year, and I think we should consider reallocating some of those funds to our research and development department.', 'B1', 3, 72, 78, '[{"index": 0, "transcript": "We need to finalize the budget proposal before the end of this week so that management can review it on Monday.", "start_ms": 0, "end_ms": 8400}, {"index": 1, "transcript": "I have been looking at the numbers from last quarter and there are a few areas where we can cut costs without affecting the quality of our services.", "start_ms": 8400, "end_ms": 19600}, {"index": 2, "transcript": "Marketing expenses have increased by twenty percent compared to the previous year, and I think we should consider reallocating some of those funds to our research and development department.", "start_ms": 19600, "end_ms": 31200}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'toeic'), 'TOEIC: Performance Review', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B1/toeic/ex-toeic-B1-002.mp3', 'I wanted to discuss your performance over the past six months. Overall, your work has been very good, particularly your contributions to the Henderson account which brought in significant revenue for the company. However, I have noticed that meeting deadlines has been a challenge, especially with the quarterly reports. I would like us to work together on creating a more structured timeline for your deliverables.', 'B1', 3, 75, 65, '[{"index": 0, "transcript": "I wanted to discuss your performance over the past six months.", "start_ms": 0, "end_ms": 4400}, {"index": 1, "transcript": "Overall, your work has been very good, particularly your contributions to the Henderson account which brought in significant revenue for the company.", "start_ms": 4400, "end_ms": 13200}, {"index": 2, "transcript": "However, I have noticed that meeting deadlines has been a challenge, especially with the quarterly reports.", "start_ms": 13200, "end_ms": 19600}, {"index": 3, "transcript": "I would like us to work together on creating a more structured timeline for your deliverables.", "start_ms": 19600, "end_ms": 26000}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'toeic'), 'TOEIC: Product Launch Meeting', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B1/toeic/ex-toeic-B1-003.mp3', 'The new product launch is scheduled for March fifteenth, which gives us exactly six weeks to finalize everything. The marketing team has already prepared the promotional materials and the social media campaign will begin two weeks before the launch date. Manufacturing confirmed that the first batch of five thousand units will be ready by March first. Our biggest concern right now is the packaging design.', 'B1', 3, 78, 65, '[{"index": 0, "transcript": "The new product launch is scheduled for March fifteenth, which gives us exactly six weeks to finalize everything.", "start_ms": 0, "end_ms": 7200}, {"index": 1, "transcript": "The marketing team has already prepared the promotional materials and the social media campaign will begin two weeks before the launch date.", "start_ms": 7200, "end_ms": 16000}, {"index": 2, "transcript": "Manufacturing confirmed that the first batch of five thousand units will be ready by March first.", "start_ms": 16000, "end_ms": 22400}, {"index": 3, "transcript": "Our biggest concern right now is the packaging design.", "start_ms": 22400, "end_ms": 26000}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'toeic'), 'TOEIC: Training Workshop Feedback', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B1/toeic/ex-toeic-B1-004.mp3', 'Thank you all for attending the customer service training workshop this morning. Before we close, I would like to gather some feedback. Please take five minutes to complete the evaluation form that was handed out at the beginning of the session. Your honest responses will help us improve future training programs. Several participants mentioned that they would like more role playing exercises.', 'B1', 3, 76, 62, '[{"index": 0, "transcript": "Thank you all for attending the customer service training workshop this morning.", "start_ms": 0, "end_ms": 4800}, {"index": 1, "transcript": "Before we close, I would like to gather some feedback.", "start_ms": 4800, "end_ms": 8800}, {"index": 2, "transcript": "Please take five minutes to complete the evaluation form that was handed out at the beginning of the session.", "start_ms": 8800, "end_ms": 16400}, {"index": 3, "transcript": "Your honest responses will help us improve future training programs.", "start_ms": 16400, "end_ms": 20400}, {"index": 4, "transcript": "Several participants mentioned that they would like more role playing exercises.", "start_ms": 20400, "end_ms": 24800}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'toeic'), 'TOEIC: Supply Chain Update', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B1/toeic/ex-toeic-B1-005.mp3', 'I am calling to update you on the status of our supply chain operations. Due to the port congestion in Shanghai, our latest shipment of electronic components has been delayed by approximately two weeks. This will affect our production schedule for the fourth quarter unless we can identify an alternative supplier within the next few days. I have already reached out to three potential vendors.', 'B1', 3, 80, 65, '[{"index": 0, "transcript": "I am calling to update you on the status of our supply chain operations.", "start_ms": 0, "end_ms": 5600}, {"index": 1, "transcript": "Due to the port congestion in Shanghai, our latest shipment of electronic components has been delayed by approximately two weeks.", "start_ms": 5600, "end_ms": 13600}, {"index": 2, "transcript": "This will affect our production schedule for the fourth quarter unless we can identify an alternative supplier within the next few days.", "start_ms": 13600, "end_ms": 22400}, {"index": 3, "transcript": "I have already reached out to three potential vendors.", "start_ms": 22400, "end_ms": 26000}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'toeic'), 'TOEIC: Quarterly Earnings Call', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B2/toeic/ex-toeic-B2-001.mp3', 'The quarterly earnings report indicates that revenue has increased by twelve percent compared to the same period last year, primarily driven by strong performance in the Asian market segment, which exceeded projections by a substantial margin. However, operating margins have contracted by approximately three percentage points due to elevated raw material costs and ongoing investments in our digital transformation initiative.', 'B2', 4, 22, 60, '[{"index": 0, "transcript": "The quarterly earnings report indicates that revenue has increased by twelve percent compared to the same period last year, primarily driven by strong performance in the Asian market segment, which exceeded projections by a substantial margin.", "start_ms": 0, "end_ms": 14400}, {"index": 1, "transcript": "However, operating margins have contracted by approximately three percentage points due to elevated raw material costs and ongoing investments in our digital transformation initiative.", "start_ms": 14400, "end_ms": 24000}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'toeic'), 'TOEIC: Merger Announcement', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B2/toeic/ex-toeic-B2-002.mp3', 'In light of the recent merger, the board of directors has decided to restructure several departments in order to eliminate redundancies and streamline operations across all regional offices. This consolidation process will take approximately nine months to complete and will involve a thorough assessment of existing roles, responsibilities, and organizational hierarchies. While we understand that organizational change can create uncertainty, I want to assure every employee that the company is committed to providing comprehensive transition support.', 'B2', 4, 30, 76, '[{"index": 0, "transcript": "In light of the recent merger, the board of directors has decided to restructure several departments in order to eliminate redundancies and streamline operations across all regional offices.", "start_ms": 0, "end_ms": 11200}, {"index": 1, "transcript": "This consolidation process will take approximately nine months to complete and will involve a thorough assessment of existing roles, responsibilities, and organizational hierarchies.", "start_ms": 11200, "end_ms": 20400}, {"index": 2, "transcript": "While we understand that organizational change can create uncertainty, I want to assure every employee that the company is committed to providing comprehensive transition support.", "start_ms": 20400, "end_ms": 30400}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'toeic'), 'TOEIC: International Expansion Strategy', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B2/toeic/ex-toeic-B2-003.mp3', 'Our international expansion strategy for the upcoming fiscal year focuses on three priority markets: Southeast Asia, Eastern Europe, and Latin America. Market research conducted over the past eighteen months has identified significant unmet demand for our products in these regions, with projected combined revenue potential of approximately four hundred and eighty million dollars over a five year horizon.', 'B2', 4, 21, 58, '[{"index": 0, "transcript": "Our international expansion strategy for the upcoming fiscal year focuses on three priority markets: Southeast Asia, Eastern Europe, and Latin America.", "start_ms": 0, "end_ms": 8400}, {"index": 1, "transcript": "Market research conducted over the past eighteen months has identified significant unmet demand for our products in these regions, with projected combined revenue potential of approximately four hundred and eighty million dollars over a five year horizon.", "start_ms": 8400, "end_ms": 23200}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'toeic'), 'TOEIC: Risk Assessment Presentation', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B2/toeic/ex-toeic-B2-004.mp3', 'The comprehensive risk assessment we conducted across all business units has identified seventeen critical vulnerabilities that require immediate attention, the most pressing of which relates to our cybersecurity infrastructure. Our current firewall architecture, which was implemented in twenty nineteen, is no longer adequate to defend against the increasingly sophisticated attack vectors that have emerged over the past three years.', 'B2', 4, 23, 59, '[{"index": 0, "transcript": "The comprehensive risk assessment we conducted across all business units has identified seventeen critical vulnerabilities that require immediate attention, the most pressing of which relates to our cybersecurity infrastructure.", "start_ms": 0, "end_ms": 11600}, {"index": 1, "transcript": "Our current firewall architecture, which was implemented in twenty nineteen, is no longer adequate to defend against the increasingly sophisticated attack vectors that have emerged over the past three years.", "start_ms": 11600, "end_ms": 23600}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'toeic'), 'TOEIC: Sustainability Report Review', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B2/toeic/ex-toeic-B2-005.mp3', 'Our annual sustainability report demonstrates measurable progress across several key environmental metrics. Carbon emissions from our manufacturing operations decreased by eighteen percent relative to the twenty twenty four baseline, exceeding our original target of fifteen percent. Water consumption per unit of production fell by twenty two percent following the implementation of our closed loop recycling system.', 'B2', 4, 22, 56, '[{"index": 0, "transcript": "Our annual sustainability report demonstrates measurable progress across several key environmental metrics.", "start_ms": 0, "end_ms": 4800}, {"index": 1, "transcript": "Carbon emissions from our manufacturing operations decreased by eighteen percent relative to the twenty twenty four baseline, exceeding our original target of fifteen percent.", "start_ms": 4800, "end_ms": 14400}, {"index": 2, "transcript": "Water consumption per unit of production fell by twenty two percent following the implementation of our closed loop recycling system.", "start_ms": 14400, "end_ms": 22400}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'toeic'), 'TOEIC: Strategic Pivot Presentation', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/C1/toeic/ex-toeic-C1-001.mp3', 'The strategic pivot we are proposing represents the most significant directional change in the company''s forty seven year history, and I want to be transparent about both the reasoning behind this recommendation and the considerable risks it entails. Our analysis of market dynamics over the past three years has revealed an unmistakable secular trend away from the hardware-centric business model that has been the foundation of our profitability since the company''s inception. Cloud-based software-as-a-service solutions are not merely complementary to our traditional product offerings; they are rapidly rendering them obsolete.', 'C1', 5, 29, 90, '[{"index": 0, "transcript": "The strategic pivot we are proposing represents the most significant directional change in the company''s forty seven year history, and I want to be transparent about both the reasoning behind this recommendation and the considerable risks it entails.", "start_ms": 0, "end_ms": 15200}, {"index": 1, "transcript": "Our analysis of market dynamics over the past three years has revealed an unmistakable secular trend away from the hardware-centric business model that has been the foundation of our profitability since the company''s inception.", "start_ms": 15200, "end_ms": 28800}, {"index": 2, "transcript": "Cloud-based software-as-a-service solutions are not merely complementary to our traditional product offerings; they are rapidly rendering them obsolete.", "start_ms": 28800, "end_ms": 36000}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'toeic'), 'TOEIC: Regulatory Compliance Briefing', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/C1/toeic/ex-toeic-C1-002.mp3', 'The regulatory landscape governing our industry has undergone a seismic transformation over the past eighteen months, with three separate jurisdictions implementing comprehensive new compliance frameworks that directly impact our operations. The European Union''s Digital Services Act imposes significant new obligations regarding content moderation, algorithmic transparency, and user data portability, while the recently enacted legislation in Singapore and Australia establishes stringent requirements around artificial intelligence governance and automated decision making systems.', 'C1', 5, 30, 70, '[{"index": 0, "transcript": "The regulatory landscape governing our industry has undergone a seismic transformation over the past eighteen months, with three separate jurisdictions implementing comprehensive new compliance frameworks that directly impact our operations.", "start_ms": 0, "end_ms": 12000}, {"index": 1, "transcript": "The European Union''s Digital Services Act imposes significant new obligations regarding content moderation, algorithmic transparency, and user data portability, while the recently enacted legislation in Singapore and Australia establishes stringent requirements around artificial intelligence governance and automated decision making systems.", "start_ms": 12000, "end_ms": 28000}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'toeic'), 'TOEIC: Innovation Lab Proposal', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/C1/toeic/ex-toeic-C1-003.mp3', 'The innovation laboratory I am proposing would operate as a semi-autonomous entity within the broader corporate structure, deliberately insulated from the quarterly earnings pressures and bureaucratic constraints that inevitably inhibit the kind of speculative, long-horizon research that produces genuinely transformative breakthroughs. Drawing on the well-documented success of similar organizational structures at companies like Google''s X division and Bell Labs during its golden era, the lab would be granted a dedicated annual budget of approximately one hundred and twenty million dollars.', 'C1', 5, 27, 80, '[{"index": 0, "transcript": "The innovation laboratory I am proposing would operate as a semi-autonomous entity within the broader corporate structure, deliberately insulated from the quarterly earnings pressures and bureaucratic constraints that inevitably inhibit the kind of speculative, long-horizon research that produces genuinely transformative breakthroughs.", "start_ms": 0, "end_ms": 16400}, {"index": 1, "transcript": "Drawing on the well-documented success of similar organizational structures at companies like Google''s X division and Bell Labs during its golden era, the lab would be granted a dedicated annual budget of approximately one hundred and twenty million dollars.", "start_ms": 16400, "end_ms": 32000}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'toeic'), 'TOEIC: Crisis Management Debrief', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/C1/toeic/ex-toeic-C1-004.mp3', 'Now that the immediate crisis has been contained, I want to conduct a thorough and unflinching examination of the institutional failures that allowed a relatively minor supply chain disruption to escalate into what became the most significant operational breakdown in the company''s history, resulting in approximately three hundred and forty million dollars in lost revenue, the departure of our three largest corporate clients, and irreparable damage to a brand reputation that took decades to build.', 'C1', 5, 25, 75, '[{"index": 0, "transcript": "Now that the immediate crisis has been contained, I want to conduct a thorough and unflinching examination of the institutional failures that allowed a relatively minor supply chain disruption to escalate into what became the most significant operational breakdown in the company''s history, resulting in approximately three hundred and forty million dollars in lost revenue, the departure of our three largest corporate clients, and irreparable damage to a brand reputation that took decades to build.", "start_ms": 0, "end_ms": 30000}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'toeic'), 'TOEIC: Board Governance Restructuring', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/C1/toeic/ex-toeic-C1-005.mp3', 'The governance restructuring proposal before you today reflects eighteen months of intensive consultation with institutional shareholders, independent governance advisors, and regulatory authorities, and represents what we believe to be the most comprehensive modernization of our corporate oversight mechanisms since the company''s initial public offering twenty three years ago. The proposal encompasses four principal elements: first, the separation of the chairman and chief executive officer roles, creating a structural balance of authority consistent with contemporary best practices in corporate governance.', 'C1', 5, 28, 79, '[{"index": 0, "transcript": "The governance restructuring proposal before you today reflects eighteen months of intensive consultation with institutional shareholders, independent governance advisors, and regulatory authorities, and represents what we believe to be the most comprehensive modernization of our corporate oversight mechanisms since the company''s initial public offering twenty three years ago.", "start_ms": 0, "end_ms": 19200}, {"index": 1, "transcript": "The proposal encompasses four principal elements: first, the separation of the chairman and chief executive officer roles, creating a structural balance of authority consistent with contemporary best practices in corporate governance.", "start_ms": 19200, "end_ms": 31600}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'ielts'), 'IELTS: Personal Introduction', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A1/ielts/ex-ielts-A1-001.mp3', 'I come from a small town near the sea. I live with my parents and my younger sister.', 'A1', 1, 7, 18, '[{"index": 0, "transcript": "I come from a small town near the sea.", "start_ms": 0, "end_ms": 3600}, {"index": 1, "transcript": "I live with my parents and my younger sister.", "start_ms": 3600, "end_ms": 7200}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'ielts'), 'IELTS: Describing Your Home', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A1/ielts/ex-ielts-A1-002.mp3', 'My house has three rooms. The kitchen is small but clean. I like my bedroom the most.', 'A1', 1, 10, 17, '[{"index": 0, "transcript": "My house has three rooms.", "start_ms": 0, "end_ms": 2000}, {"index": 1, "transcript": "The kitchen is small but clean.", "start_ms": 2000, "end_ms": 4400}, {"index": 2, "transcript": "I like my bedroom the most.", "start_ms": 4400, "end_ms": 6800}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'ielts'), 'IELTS: Daily Routine', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A1/ielts/ex-ielts-A1-003.mp3', 'I wake up at seven every morning. I eat breakfast and then go to work by bus.', 'A1', 1, 7, 17, '[{"index": 0, "transcript": "I wake up at seven every morning.", "start_ms": 0, "end_ms": 2800}, {"index": 1, "transcript": "I eat breakfast and then go to work by bus.", "start_ms": 2800, "end_ms": 6800}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'ielts'), 'IELTS: Favorite Food', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A1/ielts/ex-ielts-A1-004.mp3', 'My favorite food is rice and chicken. I eat it every day. My mother cooks very well.', 'A1', 1, 9, 17, '[{"index": 0, "transcript": "My favorite food is rice and chicken.", "start_ms": 0, "end_ms": 2800}, {"index": 1, "transcript": "I eat it every day.", "start_ms": 2800, "end_ms": 4800}, {"index": 2, "transcript": "My mother cooks very well.", "start_ms": 4800, "end_ms": 6800}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'ielts'), 'IELTS: Weather Talk', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A1/ielts/ex-ielts-A1-005.mp3', 'The weather is hot today. I like sunny days. But sometimes I enjoy the rain too.', 'A1', 1, 8, 16, '[{"index": 0, "transcript": "The weather is hot today.", "start_ms": 0, "end_ms": 2000}, {"index": 1, "transcript": "I like sunny days.", "start_ms": 2000, "end_ms": 3600}, {"index": 2, "transcript": "But sometimes I enjoy the rain too.", "start_ms": 3600, "end_ms": 6400}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'ielts'), 'IELTS: Describing a Place', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A2/ielts/ex-ielts-A2-001.mp3', 'The library is located next to the main building on the left side of the campus. It is open from eight in the morning until nine at night during weekdays. There is also a small cafe on the ground floor where students can buy coffee and snacks while they study.', 'A2', 2, 17, 50, '[{"index": 0, "transcript": "The library is located next to the main building on the left side of the campus.", "start_ms": 0, "end_ms": 6400}, {"index": 1, "transcript": "It is open from eight in the morning until nine at night during weekdays.", "start_ms": 6400, "end_ms": 12000}, {"index": 2, "transcript": "There is also a small cafe on the ground floor where students can buy coffee and snacks while they study.", "start_ms": 12000, "end_ms": 20000}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'ielts'), 'IELTS: Hobby Discussion', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A2/ielts/ex-ielts-A2-002.mp3', 'In my free time, I enjoy painting and playing the guitar. I started painting when I was twelve years old and my parents encouraged me to take art classes on the weekends. Playing the guitar is something I learned from watching online videos during the pandemic.', 'A2', 2, 18, 46, '[{"index": 0, "transcript": "In my free time, I enjoy painting and playing the guitar.", "start_ms": 0, "end_ms": 4400}, {"index": 1, "transcript": "I started painting when I was twelve years old and my parents encouraged me to take art classes on the weekends.", "start_ms": 4400, "end_ms": 12800}, {"index": 2, "transcript": "Playing the guitar is something I learned from watching online videos during the pandemic.", "start_ms": 12800, "end_ms": 18400}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'ielts'), 'IELTS: Childhood Memories', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A2/ielts/ex-ielts-A2-003.mp3', 'When I was a child, I used to play in the park every afternoon with my friends after school. We would climb trees, ride our bicycles, and sometimes we would go to the small river near our neighborhood to catch fish. Those are some of my happiest memories.', 'A2', 2, 16, 48, '[{"index": 0, "transcript": "When I was a child, I used to play in the park every afternoon with my friends after school.", "start_ms": 0, "end_ms": 7600}, {"index": 1, "transcript": "We would climb trees, ride our bicycles, and sometimes we would go to the small river near our neighborhood to catch fish.", "start_ms": 7600, "end_ms": 16400}, {"index": 2, "transcript": "Those are some of my happiest memories.", "start_ms": 16400, "end_ms": 19200}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'ielts'), 'IELTS: Public Transport', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A2/ielts/ex-ielts-A2-004.mp3', 'I usually take the bus to get to my university because it is cheaper than driving a car. The bus stop is only a five minute walk from my apartment. The journey takes about thirty minutes, and I often use that time to listen to English podcasts or read the news on my phone.', 'A2', 2, 18, 54, '[{"index": 0, "transcript": "I usually take the bus to get to my university because it is cheaper than driving a car.", "start_ms": 0, "end_ms": 7200}, {"index": 1, "transcript": "The bus stop is only a five minute walk from my apartment.", "start_ms": 7200, "end_ms": 12000}, {"index": 2, "transcript": "The journey takes about thirty minutes, and I often use that time to listen to English podcasts or read the news on my phone.", "start_ms": 12000, "end_ms": 21600}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'ielts'), 'IELTS: Describing a Friend', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A2/ielts/ex-ielts-A2-005.mp3', 'My best friend is named Linh. We have known each other since primary school and we have been close friends for more than fifteen years. She is very kind and always willing to help others. She works as a nurse at the city hospital and she is one of the most hardworking people I know.', 'A2', 2, 18, 55, '[{"index": 0, "transcript": "My best friend is named Linh.", "start_ms": 0, "end_ms": 2400}, {"index": 1, "transcript": "We have known each other since primary school and we have been close friends for more than fifteen years.", "start_ms": 2400, "end_ms": 10000}, {"index": 2, "transcript": "She is very kind and always willing to help others.", "start_ms": 10000, "end_ms": 14000}, {"index": 3, "transcript": "She works as a nurse at the city hospital and she is one of the most hardworking people I know.", "start_ms": 14000, "end_ms": 22000}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'ielts'), 'IELTS: Health and Lifestyle', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B1/ielts/ex-ielts-B1-001.mp3', 'Studies have shown that people who exercise regularly tend to have better mental health and higher levels of energy throughout the day. However, the benefits of physical activity go far beyond simply feeling more energetic. Regular exercise has been linked to improved cardiovascular function, better sleep quality, and a reduced risk of developing chronic diseases such as diabetes and hypertension.', 'B1', 3, 75, 60, '[{"index": 0, "transcript": "Studies have shown that people who exercise regularly tend to have better mental health and higher levels of energy throughout the day.", "start_ms": 0, "end_ms": 8800}, {"index": 1, "transcript": "However, the benefits of physical activity go far beyond simply feeling more energetic.", "start_ms": 8800, "end_ms": 14000}, {"index": 2, "transcript": "Regular exercise has been linked to improved cardiovascular function, better sleep quality, and a reduced risk of developing chronic diseases such as diabetes and hypertension.", "start_ms": 14000, "end_ms": 24000}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'ielts'), 'IELTS: Tourism Impact', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B1/ielts/ex-ielts-B1-002.mp3', 'Tourism can bring significant economic benefits to a region, including job creation, increased tax revenue, and investment in local infrastructure. However, when tourism is not managed sustainably, it can cause serious damage to the natural environment and disrupt the social fabric of host communities. Popular destinations often struggle with overcrowding during peak seasons.', 'B1', 3, 78, 53, '[{"index": 0, "transcript": "Tourism can bring significant economic benefits to a region, including job creation, increased tax revenue, and investment in local infrastructure.", "start_ms": 0, "end_ms": 8000}, {"index": 1, "transcript": "However, when tourism is not managed sustainably, it can cause serious damage to the natural environment and disrupt the social fabric of host communities.", "start_ms": 8000, "end_ms": 17600}, {"index": 2, "transcript": "Popular destinations often struggle with overcrowding during peak seasons.", "start_ms": 17600, "end_ms": 21200}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'ielts'), 'IELTS: Technology and Education', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B1/ielts/ex-ielts-B1-003.mp3', 'The integration of technology into the classroom has transformed the way students learn and teachers instruct. Digital tools such as interactive whiteboards, educational apps, and online learning platforms have made it possible for students to access a wealth of resources that were previously unavailable in traditional classroom settings. However, critics argue that excessive screen time can hinder the development of social skills.', 'B1', 3, 80, 62, '[{"index": 0, "transcript": "The integration of technology into the classroom has transformed the way students learn and teachers instruct.", "start_ms": 0, "end_ms": 6400}, {"index": 1, "transcript": "Digital tools such as interactive whiteboards, educational apps, and online learning platforms have made it possible for students to access a wealth of resources that were previously unavailable in traditional classroom settings.", "start_ms": 6400, "end_ms": 19200}, {"index": 2, "transcript": "However, critics argue that excessive screen time can hinder the development of social skills.", "start_ms": 19200, "end_ms": 24800}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'ielts'), 'IELTS: Urban vs Rural Life', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B1/ielts/ex-ielts-B1-004.mp3', 'The debate between urban and rural living is one that has engaged sociologists and policymakers for decades. Cities offer a wider range of employment opportunities, cultural experiences, and educational institutions, making them attractive to young professionals. On the other hand, rural areas provide a quieter, less stressful environment with stronger community bonds and closer access to nature.', 'B1', 3, 25, 57, '[{"index": 0, "transcript": "The debate between urban and rural living is one that has engaged sociologists and policymakers for decades.", "start_ms": 0, "end_ms": 6800}, {"index": 1, "transcript": "Cities offer a wider range of employment opportunities, cultural experiences, and educational institutions, making them attractive to young professionals.", "start_ms": 6800, "end_ms": 14400}, {"index": 2, "transcript": "On the other hand, rural areas provide a quieter, less stressful environment with stronger community bonds and closer access to nature.", "start_ms": 14400, "end_ms": 22800}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'ielts'), 'IELTS: Environmental Awareness', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B1/ielts/ex-ielts-B1-005.mp3', 'Environmental awareness among young people has increased dramatically over the past decade, driven largely by the visibility of climate change impacts and the influence of social media campaigns highlighting ecological issues. Many students now participate in school recycling programs, volunteer for beach cleanup activities, and advocate for sustainable practices within their communities.', 'B1', 3, 23, 52, '[{"index": 0, "transcript": "Environmental awareness among young people has increased dramatically over the past decade, driven largely by the visibility of climate change impacts and the influence of social media campaigns highlighting ecological issues.", "start_ms": 0, "end_ms": 12400}, {"index": 1, "transcript": "Many students now participate in school recycling programs, volunteer for beach cleanup activities, and advocate for sustainable practices within their communities.", "start_ms": 12400, "end_ms": 20800}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'ielts'), 'IELTS: Urbanization and Social Challenges', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B2/ielts/ex-ielts-B2-001.mp3', 'The rapid pace of urbanization in developing countries has led to a range of social and environmental challenges, including overcrowding, pollution, and inadequate public infrastructure that struggles to keep pace with population growth. In many rapidly expanding cities across Africa and South Asia, the influx of rural migrants seeking economic opportunity has outstripped the capacity of municipal authorities to provide basic services such as clean water, sanitation, and reliable electricity.', 'B2', 4, 27, 70, '[{"index": 0, "transcript": "The rapid pace of urbanization in developing countries has led to a range of social and environmental challenges, including overcrowding, pollution, and inadequate public infrastructure that struggles to keep pace with population growth.", "start_ms": 0, "end_ms": 13200}, {"index": 1, "transcript": "In many rapidly expanding cities across Africa and South Asia, the influx of rural migrants seeking economic opportunity has outstripped the capacity of municipal authorities to provide basic services such as clean water, sanitation, and reliable electricity.", "start_ms": 13200, "end_ms": 28000}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'ielts'), 'IELTS: Technology and Social Progress', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B2/ielts/ex-ielts-B2-002.mp3', 'The notion that technological advancement inevitably leads to social progress is a fundamentally flawed assumption, as history has repeatedly demonstrated that innovation without ethical oversight can exacerbate existing inequalities rather than resolve them. The industrial revolution, often celebrated as the engine of modern prosperity, simultaneously created conditions of extreme exploitation that took decades of social reform to address.', 'B2', 4, 23, 58, '[{"index": 0, "transcript": "The notion that technological advancement inevitably leads to social progress is a fundamentally flawed assumption, as history has repeatedly demonstrated that innovation without ethical oversight can exacerbate existing inequalities rather than resolve them.", "start_ms": 0, "end_ms": 13200}, {"index": 1, "transcript": "The industrial revolution, often celebrated as the engine of modern prosperity, simultaneously created conditions of extreme exploitation that took decades of social reform to address.", "start_ms": 13200, "end_ms": 23200}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'ielts'), 'IELTS: Globalization Debate', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B2/ielts/ex-ielts-B2-003.mp3', 'The contemporary debate surrounding globalization has become increasingly polarized, with proponents emphasizing its role in lifting hundreds of millions of people out of extreme poverty and facilitating unprecedented cross-cultural exchange, while critics highlight the erosion of local traditions, the exploitation of workers in developing nations, and the environmental degradation associated with global supply chains.', 'B2', 4, 22, 54, '[{"index": 0, "transcript": "The contemporary debate surrounding globalization has become increasingly polarized, with proponents emphasizing its role in lifting hundreds of millions of people out of extreme poverty and facilitating unprecedented cross-cultural exchange, while critics highlight the erosion of local traditions, the exploitation of workers in developing nations, and the environmental degradation associated with global supply chains.", "start_ms": 0, "end_ms": 21600}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'ielts'), 'IELTS: Psychology of Procrastination', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B2/ielts/ex-ielts-B2-004.mp3', 'Procrastination, far from being a simple matter of laziness or poor time management as it is commonly perceived, represents a complex psychological phenomenon rooted in the brain''s difficulty reconciling immediate emotional needs with long-term rational objectives. Neuroscientific research has revealed that chronic procrastinators exhibit significantly reduced activity in the prefrontal cortex, the region responsible for executive function and impulse control.', 'B2', 4, 24, 60, '[{"index": 0, "transcript": "Procrastination, far from being a simple matter of laziness or poor time management as it is commonly perceived, represents a complex psychological phenomenon rooted in the brain''s difficulty reconciling immediate emotional needs with long-term rational objectives.", "start_ms": 0, "end_ms": 14400}, {"index": 1, "transcript": "Neuroscientific research has revealed that chronic procrastinators exhibit significantly reduced activity in the prefrontal cortex, the region responsible for executive function and impulse control.", "start_ms": 14400, "end_ms": 24000}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'ielts'), 'IELTS: History of Scientific Discovery', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B2/ielts/ex-ielts-B2-005.mp3', 'The history of scientific discovery is replete with instances in which breakthroughs emerged not from systematic methodological rigor but from accidental observations, intuitive leaps, and the willingness of individual researchers to pursue lines of inquiry that their contemporaries dismissed as misguided or irrelevant. Alexander Fleming''s discovery of penicillin, often cited as the quintessential example of serendipity in science, required not merely the accident of a contaminated petri dish but also Fleming''s unusual capacity to recognize the significance of an unexpected observation.', 'B2', 4, 32, 81, '[{"index": 0, "transcript": "The history of scientific discovery is replete with instances in which breakthroughs emerged not from systematic methodological rigor but from accidental observations, intuitive leaps, and the willingness of individual researchers to pursue lines of inquiry that their contemporaries dismissed as misguided or irrelevant.", "start_ms": 0, "end_ms": 17200}, {"index": 1, "transcript": "Alexander Fleming''s discovery of penicillin, often cited as the quintessential example of serendipity in science, required not merely the accident of a contaminated petri dish but also Fleming''s unusual capacity to recognize the significance of an unexpected observation.", "start_ms": 17200, "end_ms": 32400}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'ielts'), 'IELTS: Philosophy of Justice', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/C1/ielts/ex-ielts-C1-001.mp3', 'The question of what constitutes a just society has occupied philosophical discourse since the ancient Greeks, yet the frameworks we deploy to evaluate justice remain fundamentally contested in ways that have profound implications for contemporary policy debates. John Rawls'' influential theory of justice as fairness, articulated in his landmark nineteen seventy one work, proposes that the principles governing the basic structure of society should be those that rational individuals would choose from behind a veil of ignorance, a hypothetical condition in which one lacks knowledge of one''s own social position.', 'C1', 5, 30, 90, '[{"index": 0, "transcript": "The question of what constitutes a just society has occupied philosophical discourse since the ancient Greeks, yet the frameworks we deploy to evaluate justice remain fundamentally contested in ways that have profound implications for contemporary policy debates.", "start_ms": 0, "end_ms": 14800}, {"index": 1, "transcript": "John Rawls'' influential theory of justice as fairness, articulated in his landmark nineteen seventy one work, proposes that the principles governing the basic structure of society should be those that rational individuals would choose from behind a veil of ignorance, a hypothetical condition in which one lacks knowledge of one''s own social position.", "start_ms": 14800, "end_ms": 36000}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'ielts'), 'IELTS: Neuroscience of Memory', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/C1/ielts/ex-ielts-C1-002.mp3', 'The neuroscience of human memory has undergone a revolutionary transformation over the past two decades, fundamentally altering our understanding of how experiences are encoded, consolidated, and retrieved within the neural architecture of the brain. Contrary to the intuitively appealing but empirically untenable metaphor of memory as a faithful recording device that stores experiences in fixed form for later playback, contemporary research has established that memories are actively reconstructed each time they are accessed.', 'C1', 5, 25, 73, '[{"index": 0, "transcript": "The neuroscience of human memory has undergone a revolutionary transformation over the past two decades, fundamentally altering our understanding of how experiences are encoded, consolidated, and retrieved within the neural architecture of the brain.", "start_ms": 0, "end_ms": 13600}, {"index": 1, "transcript": "Contrary to the intuitively appealing but empirically untenable metaphor of memory as a faithful recording device that stores experiences in fixed form for later playback, contemporary research has established that memories are actively reconstructed each time they are accessed.", "start_ms": 13600, "end_ms": 29200}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'ielts'), 'IELTS: Climate Economics Analysis', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/C1/ielts/ex-ielts-C1-003.mp3', 'The economic analysis of climate change mitigation strategies is complicated by what economists term the problem of intertemporal discounting, the methodological challenge of assigning present value to costs and benefits that will materialize decades or centuries in the future. The choice of discount rate, a seemingly technical parameter buried deep within economic models, turns out to have enormous implications for policy recommendations.', 'C1', 5, 22, 62, '[{"index": 0, "transcript": "The economic analysis of climate change mitigation strategies is complicated by what economists term the problem of intertemporal discounting, the methodological challenge of assigning present value to costs and benefits that will materialize decades or centuries in the future.", "start_ms": 0, "end_ms": 15600}, {"index": 1, "transcript": "The choice of discount rate, a seemingly technical parameter buried deep within economic models, turns out to have enormous implications for policy recommendations.", "start_ms": 15600, "end_ms": 24800}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'ielts'), 'IELTS: Sociology of Digital Identity', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/C1/ielts/ex-ielts-C1-004.mp3', 'The proliferation of digital platforms has inaugurated an unprecedented era in the construction and performance of human identity, one in which the traditional distinction between authentic selfhood and social presentation has become increasingly difficult to maintain with any intellectual coherence. Erving Goffman''s dramaturgical framework, which conceptualized social interaction as a form of theatrical performance in which individuals manage impressions through careful manipulation of frontstage and backstage behavior, acquires renewed relevance in the context of social media environments.', 'C1', 5, 28, 77, '[{"index": 0, "transcript": "The proliferation of digital platforms has inaugurated an unprecedented era in the construction and performance of human identity, one in which the traditional distinction between authentic selfhood and social presentation has become increasingly difficult to maintain with any intellectual coherence.", "start_ms": 0, "end_ms": 16000}, {"index": 1, "transcript": "Erving Goffman''s dramaturgical framework, which conceptualized social interaction as a form of theatrical performance in which individuals manage impressions through careful manipulation of frontstage and backstage behavior, acquires renewed relevance in the context of social media environments.", "start_ms": 16000, "end_ms": 30800}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'ielts'), 'IELTS: Biodiversity and Ecosystem Services', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/C1/ielts/ex-ielts-C1-005.mp3', 'The accelerating loss of global biodiversity represents what many ecologists now characterize as the sixth mass extinction event in the four point five billion year history of life on Earth, with current species disappearance rates estimated to be between one hundred and one thousand times the natural background rate that prevailed throughout most of geological history. While the conservation argument has traditionally been framed in terms of the intrinsic value of biological diversity, there is growing recognition that biodiversity loss also poses an existential threat to human economic systems through the degradation of ecosystem services upon which civilization fundamentally depends.', 'C1', 5, 34, 100, '[{"index": 0, "transcript": "The accelerating loss of global biodiversity represents what many ecologists now characterize as the sixth mass extinction event in the four point five billion year history of life on Earth, with current species disappearance rates estimated to be between one hundred and one thousand times the natural background rate that prevailed throughout most of geological history.", "start_ms": 0, "end_ms": 22400}, {"index": 1, "transcript": "While the conservation argument has traditionally been framed in terms of the intrinsic value of biological diversity, there is growing recognition that biodiversity loss also poses an existential threat to human economic systems through the degradation of ecosystem services upon which civilization fundamentally depends.", "start_ms": 22400, "end_ms": 40000}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'daily-conversation'), 'Morning Greeting at the Office', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A1/daily-conversation/ex-daily-A1-001.mp3', 'Good morning. How are you today? I am fine, thank you. And you?', 'A1', 1, 9, 13, '[{"index": 0, "transcript": "Good morning.", "start_ms": 0, "end_ms": 1500}, {"index": 1, "transcript": "How are you today?", "start_ms": 1500, "end_ms": 3100}, {"index": 2, "transcript": "I am fine, thank you.", "start_ms": 3100, "end_ms": 5100}, {"index": 3, "transcript": "And you?", "start_ms": 5100, "end_ms": 6600}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'daily-conversation'), 'Ordering Water at a Restaurant', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A1/daily-conversation/ex-daily-A1-002.mp3', 'I would like a glass of water, please. And can I see the menu? Thank you.', 'A1', 1, 7, 16, '[{"index": 0, "transcript": "I would like a glass of water, please.", "start_ms": 0, "end_ms": 3200}, {"index": 1, "transcript": "And can I see the menu?", "start_ms": 3200, "end_ms": 5600}, {"index": 2, "transcript": "Thank you.", "start_ms": 5600, "end_ms": 7100}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'daily-conversation'), 'Asking for the Time', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A1/daily-conversation/ex-daily-A1-003.mp3', 'Excuse me, what time is it? It is half past three. Thank you very much.', 'A1', 1, 9, 15, '[{"index": 0, "transcript": "Excuse me, what time is it?", "start_ms": 0, "end_ms": 2400}, {"index": 1, "transcript": "It is half past three.", "start_ms": 2400, "end_ms": 4400}, {"index": 2, "transcript": "Thank you very much.", "start_ms": 4400, "end_ms": 6000}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'daily-conversation'), 'At the Grocery Store', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A1/daily-conversation/ex-daily-A1-004.mp3', 'I need some milk, bread, and eggs. How much is this? That is five dollars.', 'A1', 1, 8, 15, '[{"index": 0, "transcript": "I need some milk, bread, and eggs.", "start_ms": 0, "end_ms": 2800}, {"index": 1, "transcript": "How much is this?", "start_ms": 2800, "end_ms": 4400}, {"index": 2, "transcript": "That is five dollars.", "start_ms": 4400, "end_ms": 6000}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'daily-conversation'), 'Introducing a Friend', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A1/daily-conversation/ex-daily-A1-005.mp3', 'This is my friend Tom. He is a teacher. He comes from Australia. Say hello to him.', 'A1', 1, 11, 17, '[{"index": 0, "transcript": "This is my friend Tom.", "start_ms": 0, "end_ms": 2000}, {"index": 1, "transcript": "He is a teacher.", "start_ms": 2000, "end_ms": 3600}, {"index": 2, "transcript": "He comes from Australia.", "start_ms": 3600, "end_ms": 5200}, {"index": 3, "transcript": "Say hello to him.", "start_ms": 5200, "end_ms": 6800}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'daily-conversation'), 'Shopping for Clothes', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A2/daily-conversation/ex-daily-A2-001.mp3', 'Excuse me, do you have this shirt in a different color or size? I am looking for a medium in blue. The small one is too tight. Could you also tell me if there is a fitting room nearby where I can try it on?', 'A2', 2, 16, 45, '[{"index": 0, "transcript": "Excuse me, do you have this shirt in a different color or size?", "start_ms": 0, "end_ms": 5200}, {"index": 1, "transcript": "I am looking for a medium in blue.", "start_ms": 5200, "end_ms": 8400}, {"index": 2, "transcript": "The small one is too tight.", "start_ms": 8400, "end_ms": 10800}, {"index": 3, "transcript": "Could you also tell me if there is a fitting room nearby where I can try it on?", "start_ms": 10800, "end_ms": 18000}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'daily-conversation'), 'Making a Doctor Appointment', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A2/daily-conversation/ex-daily-A2-002.mp3', 'Hello, I would like to make an appointment with Doctor Lee. I have not been feeling well for the past few days. I have a sore throat and a headache. Is there any time available tomorrow morning? I can come at any time before noon.', 'A2', 2, 16, 45, '[{"index": 0, "transcript": "Hello, I would like to make an appointment with Doctor Lee.", "start_ms": 0, "end_ms": 4400}, {"index": 1, "transcript": "I have not been feeling well for the past few days.", "start_ms": 4400, "end_ms": 8800}, {"index": 2, "transcript": "I have a sore throat and a headache.", "start_ms": 8800, "end_ms": 12000}, {"index": 3, "transcript": "Is there any time available tomorrow morning?", "start_ms": 12000, "end_ms": 14800}, {"index": 4, "transcript": "I can come at any time before noon.", "start_ms": 14800, "end_ms": 18000}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'daily-conversation'), 'Asking for Directions', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A2/daily-conversation/ex-daily-A2-003.mp3', 'Excuse me, could you tell me how to get to the nearest train station? I am not from around here and I have been walking for twenty minutes without finding it. Is it far from here? Should I take a bus or can I walk there?', 'A2', 2, 17, 46, '[{"index": 0, "transcript": "Excuse me, could you tell me how to get to the nearest train station?", "start_ms": 0, "end_ms": 5600}, {"index": 1, "transcript": "I am not from around here and I have been walking for twenty minutes without finding it.", "start_ms": 5600, "end_ms": 12400}, {"index": 2, "transcript": "Is it far from here?", "start_ms": 12400, "end_ms": 14400}, {"index": 3, "transcript": "Should I take a bus or can I walk there?", "start_ms": 14400, "end_ms": 18400}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'daily-conversation'), 'Weekend Plans with Friends', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A2/daily-conversation/ex-daily-A2-004.mp3', 'What are you doing this Saturday? I was thinking we could go to the movies. There is a new action film that looks really exciting. After the movie, we could grab dinner at that Italian restaurant near the cinema. What do you think?', 'A2', 2, 15, 43, '[{"index": 0, "transcript": "What are you doing this Saturday?", "start_ms": 0, "end_ms": 2400}, {"index": 1, "transcript": "I was thinking we could go to the movies.", "start_ms": 2400, "end_ms": 6000}, {"index": 2, "transcript": "There is a new action film that looks really exciting.", "start_ms": 6000, "end_ms": 10000}, {"index": 3, "transcript": "After the movie, we could grab dinner at that Italian restaurant near the cinema.", "start_ms": 10000, "end_ms": 15600}, {"index": 4, "transcript": "What do you think?", "start_ms": 15600, "end_ms": 17200}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'daily-conversation'), 'Checking into a Hotel', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A2/daily-conversation/ex-daily-A2-005.mp3', 'Good evening. I have a reservation under the name of Nguyen. I booked a double room for three nights through your website last week. Could you please confirm the check-out time? Also, does the room rate include breakfast?', 'A2', 2, 17, 38, '[{"index": 0, "transcript": "Good evening.", "start_ms": 0, "end_ms": 1500}, {"index": 1, "transcript": "I have a reservation under the name of Nguyen.", "start_ms": 1500, "end_ms": 5100}, {"index": 2, "transcript": "I booked a double room for three nights through your website last week.", "start_ms": 5100, "end_ms": 10300}, {"index": 3, "transcript": "Could you please confirm the check-out time?", "start_ms": 10300, "end_ms": 13100}, {"index": 4, "transcript": "Also, does the room rate include breakfast?", "start_ms": 13100, "end_ms": 15900}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'daily-conversation'), 'Discussing Weekend Hiking Plans', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B1/daily-conversation/ex-daily-B1-001.mp3', 'I was thinking we could go hiking this Saturday morning and then maybe grab some lunch at that new restaurant downtown. The weather forecast says it will be clear and sunny with temperatures around twenty two degrees, which would be perfect for the mountain trail. We should probably leave around seven in the morning to avoid the midday heat.', 'B1', 3, 19, 59, '[{"index": 0, "transcript": "I was thinking we could go hiking this Saturday morning and then maybe grab some lunch at that new restaurant downtown.", "start_ms": 0, "end_ms": 8400}, {"index": 1, "transcript": "The weather forecast says it will be clear and sunny with temperatures around twenty two degrees, which would be perfect for the mountain trail.", "start_ms": 8400, "end_ms": 18000}, {"index": 2, "transcript": "We should probably leave around seven in the morning to avoid the midday heat.", "start_ms": 18000, "end_ms": 23600}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'daily-conversation'), 'Negotiating with a Landlord', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B1/daily-conversation/ex-daily-B1-002.mp3', 'I appreciate you taking the time to meet with me today. I have really enjoyed living in this apartment for the past two years, but I wanted to discuss the proposed rent increase. A fifteen percent increase seems quite steep considering that several units in this building have been vacant for months. I would like to suggest a more modest increase of five percent.', 'B1', 3, 19, 64, '[{"index": 0, "transcript": "I appreciate you taking the time to meet with me today.", "start_ms": 0, "end_ms": 4400}, {"index": 1, "transcript": "I have really enjoyed living in this apartment for the past two years, but I wanted to discuss the proposed rent increase.", "start_ms": 4400, "end_ms": 13200}, {"index": 2, "transcript": "A fifteen percent increase seems quite steep considering that several units in this building have been vacant for months.", "start_ms": 13200, "end_ms": 20800}, {"index": 3, "transcript": "I would like to suggest a more modest increase of five percent.", "start_ms": 20800, "end_ms": 25600}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'daily-conversation'), 'Returning a Defective Product', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B1/daily-conversation/ex-daily-B1-003.mp3', 'I purchased this laptop from your store two weeks ago and I have been experiencing several problems with it. The screen flickers constantly and the battery only lasts about ninety minutes before needing to be recharged. I have already tried restarting it multiple times and updating the software but nothing has helped. According to your return policy, I should be eligible for either a full refund or a replacement.', 'B1', 3, 25, 69, '[{"index": 0, "transcript": "I purchased this laptop from your store two weeks ago and I have been experiencing several problems with it.", "start_ms": 0, "end_ms": 7600}, {"index": 1, "transcript": "The screen flickers constantly and the battery only lasts about ninety minutes before needing to be recharged.", "start_ms": 7600, "end_ms": 14400}, {"index": 2, "transcript": "I have already tried restarting it multiple times and updating the software but nothing has helped.", "start_ms": 14400, "end_ms": 20800}, {"index": 3, "transcript": "According to your return policy, I should be eligible for either a full refund or a replacement.", "start_ms": 20800, "end_ms": 27600}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'daily-conversation'), 'Planning a Birthday Party', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B1/daily-conversation/ex-daily-B1-004.mp3', 'My daughter is turning seven next weekend and I want to throw her a birthday party at the park. I was thinking of inviting about fifteen kids from her class and maybe setting up some games and a bouncy castle. The tricky part is the food because several of the children have allergies. One is allergic to nuts, two cannot eat gluten, and one is lactose intolerant.', 'B1', 3, 20, 67, '[{"index": 0, "transcript": "My daughter is turning seven next weekend and I want to throw her a birthday party at the park.", "start_ms": 0, "end_ms": 7600}, {"index": 1, "transcript": "I was thinking of inviting about fifteen kids from her class and maybe setting up some games and a bouncy castle.", "start_ms": 7600, "end_ms": 16000}, {"index": 2, "transcript": "The tricky part is the food because several of the children have allergies.", "start_ms": 16000, "end_ms": 21200}, {"index": 3, "transcript": "One is allergic to nuts, two cannot eat gluten, and one is lactose intolerant.", "start_ms": 21200, "end_ms": 26800}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'daily-conversation'), 'Car Trouble at the Mechanic', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B1/daily-conversation/ex-daily-B1-005.mp3', 'I brought my car in because there is a strange noise coming from the engine whenever I accelerate above sixty kilometers per hour. It started about a week ago and it has been getting louder every day. I also noticed that the car pulls slightly to the right when I brake, which is making me worried about driving on the highway.', 'B1', 3, 19, 61, '[{"index": 0, "transcript": "I brought my car in because there is a strange noise coming from the engine whenever I accelerate above sixty kilometers per hour.", "start_ms": 0, "end_ms": 9200}, {"index": 1, "transcript": "It started about a week ago and it has been getting louder every day.", "start_ms": 9200, "end_ms": 14800}, {"index": 2, "transcript": "I also noticed that the car pulls slightly to the right when I brake, which is making me worried about driving on the highway.", "start_ms": 14800, "end_ms": 24400}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'daily-conversation'), 'Debating Career Change Plans', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B2/daily-conversation/ex-daily-B2-001.mp3', 'I have been considering a career change for quite some time now, and I think pursuing a degree in data science might open up some interesting opportunities for me in the long run. The problem is that going back to university at thirty five feels like a significant risk, especially when I consider the financial implications of giving up a stable salary for two years. My current position in marketing is comfortable and pays well, but I cannot shake the feeling that the field is becoming increasingly automated.', 'B2', 4, 26, 88, '[{"index": 0, "transcript": "I have been considering a career change for quite some time now, and I think pursuing a degree in data science might open up some interesting opportunities for me in the long run.", "start_ms": 0, "end_ms": 13200}, {"index": 1, "transcript": "The problem is that going back to university at thirty five feels like a significant risk, especially when I consider the financial implications of giving up a stable salary for two years.", "start_ms": 13200, "end_ms": 26000}, {"index": 2, "transcript": "My current position in marketing is comfortable and pays well, but I cannot shake the feeling that the field is becoming increasingly automated.", "start_ms": 26000, "end_ms": 35200}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'daily-conversation'), 'Discussing Neighborhood Gentrification', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B2/daily-conversation/ex-daily-B2-002.mp3', 'Have you noticed how much the neighborhood has changed over the past three years? When we first moved here, there was the old bookshop on the corner, the family bakery that had been there for forty years, and that community center where all the kids used to play basketball after school. Now there is an organic juice bar, a boutique fitness studio, and a coworking space that charges two hundred dollars a month for a hot desk.', 'B2', 4, 20, 77, '[{"index": 0, "transcript": "Have you noticed how much the neighborhood has changed over the past three years?", "start_ms": 0, "end_ms": 5600}, {"index": 1, "transcript": "When we first moved here, there was the old bookshop on the corner, the family bakery that had been there for forty years, and that community center where all the kids used to play basketball after school.", "start_ms": 5600, "end_ms": 20400}, {"index": 2, "transcript": "Now there is an organic juice bar, a boutique fitness studio, and a coworking space that charges two hundred dollars a month for a hot desk.", "start_ms": 20400, "end_ms": 30800}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'daily-conversation'), 'Parenting Philosophy Discussion', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B2/daily-conversation/ex-daily-B2-003.mp3', 'My wife and I have been having an ongoing debate about our approach to parenting that I suspect reflects a much broader generational divide. She believes strongly in what some psychologists call authoritative parenting, which involves setting clear boundaries and expectations while maintaining warmth and open communication. I lean more toward a free range approach, where children are given significantly more autonomy to make their own decisions and learn from natural consequences.', 'B2', 4, 25, 72, '[{"index": 0, "transcript": "My wife and I have been having an ongoing debate about our approach to parenting that I suspect reflects a much broader generational divide.", "start_ms": 0, "end_ms": 9600}, {"index": 1, "transcript": "She believes strongly in what some psychologists call authoritative parenting, which involves setting clear boundaries and expectations while maintaining warmth and open communication.", "start_ms": 9600, "end_ms": 18800}, {"index": 2, "transcript": "I lean more toward a free range approach, where children are given significantly more autonomy to make their own decisions and learn from natural consequences.", "start_ms": 18800, "end_ms": 28800}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'daily-conversation'), 'Ethical Consumerism Conversation', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B2/daily-conversation/ex-daily-B2-004.mp3', 'I have been trying to be more conscious about my purchasing decisions lately, but the more research I do, the more overwhelming and contradictory the information becomes. Take coffee for example. I switched to fair trade certified beans thinking I was making an ethical choice, only to discover that the certification process is riddled with loopholes and that a significant portion of the premium consumers pay never actually reaches the farmers.', 'B2', 4, 22, 71, '[{"index": 0, "transcript": "I have been trying to be more conscious about my purchasing decisions lately, but the more research I do, the more overwhelming and contradictory the information becomes.", "start_ms": 0, "end_ms": 10800}, {"index": 1, "transcript": "Take coffee for example.", "start_ms": 10800, "end_ms": 12400}, {"index": 2, "transcript": "I switched to fair trade certified beans thinking I was making an ethical choice, only to discover that the certification process is riddled with loopholes and that a significant portion of the premium consumers pay never actually reaches the farmers.", "start_ms": 12400, "end_ms": 28400}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'daily-conversation'), 'Mental Health Awareness Chat', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B2/daily-conversation/ex-daily-B2-005.mp3', 'Something I wish more people understood about anxiety is that it does not always manifest as visible nervousness or panic attacks. For years, my anxiety presented itself as perfectionism, an inability to delegate tasks at work, and a compulsive need to plan every detail of every day weeks in advance. People around me interpreted these behaviors as admirable qualities rather than symptoms of an underlying condition that was slowly eroding my capacity for spontaneity.', 'B2', 4, 26, 74, '[{"index": 0, "transcript": "Something I wish more people understood about anxiety is that it does not always manifest as visible nervousness or panic attacks.", "start_ms": 0, "end_ms": 8400}, {"index": 1, "transcript": "For years, my anxiety presented itself as perfectionism, an inability to delegate tasks at work, and a compulsive need to plan every detail of every day weeks in advance.", "start_ms": 8400, "end_ms": 20000}, {"index": 2, "transcript": "People around me interpreted these behaviors as admirable qualities rather than symptoms of an underlying condition that was slowly eroding my capacity for spontaneity.", "start_ms": 20000, "end_ms": 29600}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'daily-conversation'), 'Philosophy of Authenticity in Social Media', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/C1/daily-conversation/ex-daily-C1-001.mp3', 'While social media platforms have undeniably transformed the way we communicate and access information, there is growing concern among psychologists that prolonged exposure to curated online personas may be contributing to a significant rise in anxiety and self-esteem issues, particularly among adolescents and young adults whose sense of identity is still in the formative stages of development. What I find most philosophically troubling about this phenomenon is not the well-documented mental health consequences but rather the more subtle epistemic damage that occurs when an entire generation internalizes the assumption that identity is fundamentally performative.', 'C1', 5, 31, 94, '[{"index": 0, "transcript": "While social media platforms have undeniably transformed the way we communicate and access information, there is growing concern among psychologists that prolonged exposure to curated online personas may be contributing to a significant rise in anxiety and self-esteem issues, particularly among adolescents and young adults whose sense of identity is still in the formative stages of development.", "start_ms": 0, "end_ms": 22800}, {"index": 1, "transcript": "What I find most philosophically troubling about this phenomenon is not the well-documented mental health consequences but rather the more subtle epistemic damage that occurs when an entire generation internalizes the assumption that identity is fundamentally performative.", "start_ms": 22800, "end_ms": 37600}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'daily-conversation'), 'Intergenerational Wealth Discussion', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/C1/daily-conversation/ex-daily-C1-002.mp3', 'The conversation about intergenerational wealth transfer that most families avoid is precisely the one that has the most profound implications for how inequality perpetuates itself across time. My grandparents were able to purchase their home in nineteen sixty two for what would be the equivalent of approximately eighteen months of a factory worker''s salary, an investment that has appreciated in value by roughly twelve hundred percent over six decades and now constitutes the single largest asset in our family''s financial portfolio.', 'C1', 5, 23, 81, '[{"index": 0, "transcript": "The conversation about intergenerational wealth transfer that most families avoid is precisely the one that has the most profound implications for how inequality perpetuates itself across time.", "start_ms": 0, "end_ms": 10800}, {"index": 1, "transcript": "My grandparents were able to purchase their home in nineteen sixty two for what would be the equivalent of approximately eighteen months of a factory worker''s salary, an investment that has appreciated in value by roughly twelve hundred percent over six decades and now constitutes the single largest asset in our family''s financial portfolio.", "start_ms": 10800, "end_ms": 32400}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'daily-conversation'), 'The Attention Economy Critique', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/C1/daily-conversation/ex-daily-C1-003.mp3', 'We are living through what might retrospectively be recognized as one of the most consequential transformations in human cognitive history, the wholesale colonization of human attention by commercial interests whose business models depend upon the systematic exploitation of psychological vulnerabilities that evolution designed for entirely different purposes. The dopamine-driven feedback loops that social media platforms and digital entertainment services employ to maximize user engagement are not incidental features of their design but rather the central mechanism through which these companies generate the sustained attention that constitutes their primary commercial product.', 'C1', 5, 30, 90, '[{"index": 0, "transcript": "We are living through what might retrospectively be recognized as one of the most consequential transformations in human cognitive history, the wholesale colonization of human attention by commercial interests whose business models depend upon the systematic exploitation of psychological vulnerabilities that evolution designed for entirely different purposes.", "start_ms": 0, "end_ms": 18800}, {"index": 1, "transcript": "The dopamine-driven feedback loops that social media platforms and digital entertainment services employ to maximize user engagement are not incidental features of their design but rather the central mechanism through which these companies generate the sustained attention that constitutes their primary commercial product.", "start_ms": 18800, "end_ms": 36000}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'daily-conversation'), 'Mortality and Legacy Reflection', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/C1/daily-conversation/ex-daily-C1-004.mp3', 'The older I get, the more frequently I find myself returning to a question that most people, understandably, prefer to avoid: what, if anything, survives the extinction of individual consciousness, and does the answer to that question have any bearing on how one ought to live? The secular humanist tradition offers the consolation of legacy, the idea that we persist through the memories of those who loved us, through the institutions we helped build, through the children we raised and the values we transmitted to them across the dinner table and through a thousand small, seemingly inconsequential daily interactions.', 'C1', 5, 27, 99, '[{"index": 0, "transcript": "The older I get, the more frequently I find myself returning to a question that most people, understandably, prefer to avoid: what, if anything, survives the extinction of individual consciousness, and does the answer to that question have any bearing on how one ought to live?", "start_ms": 0, "end_ms": 18400}, {"index": 1, "transcript": "The secular humanist tradition offers the consolation of legacy, the idea that we persist through the memories of those who loved us, through the institutions we helped build, through the children we raised and the values we transmitted to them across the dinner table and through a thousand small, seemingly inconsequential daily interactions.", "start_ms": 18400, "end_ms": 39600}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'daily-conversation'), 'Education System Philosophy Debate', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/C1/daily-conversation/ex-daily-C1-005.mp3', 'The fundamental question that education systems worldwide continue to evade, despite two centuries of compulsory schooling and trillions of dollars in cumulative investment, is whether the primary purpose of education is to produce economically productive citizens who can contribute to national prosperity, or to cultivate autonomous individuals capable of leading examined lives and participating meaningfully in democratic self-governance. The tension between these two objectives, which are not inherently contradictory but which in practice tend to pull institutional priorities in divergent directions, manifests in virtually every significant educational policy debate.', 'C1', 5, 32, 89, '[{"index": 0, "transcript": "The fundamental question that education systems worldwide continue to evade, despite two centuries of compulsory schooling and trillions of dollars in cumulative investment, is whether the primary purpose of education is to produce economically productive citizens who can contribute to national prosperity, or to cultivate autonomous individuals capable of leading examined lives and participating meaningfully in democratic self-governance.", "start_ms": 0, "end_ms": 23200}, {"index": 1, "transcript": "The tension between these two objectives, which are not inherently contradictory but which in practice tend to pull institutional priorities in divergent directions, manifests in virtually every significant educational policy debate.", "start_ms": 23200, "end_ms": 35600}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'podcasts'), 'Podcast: Welcome to the Show', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A1/podcasts/ex-podcast-A1-001.mp3', 'Welcome to our show. Let us begin. Today we will talk about animals.', 'A1', 1, 8, 13, '[{"index": 0, "transcript": "Welcome to our show.", "start_ms": 0, "end_ms": 1600}, {"index": 1, "transcript": "Let us begin.", "start_ms": 1600, "end_ms": 3100}, {"index": 2, "transcript": "Today we will talk about animals.", "start_ms": 3100, "end_ms": 5500}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'podcasts'), 'Podcast: My Favorite Color', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A1/podcasts/ex-podcast-A1-002.mp3', 'My favorite color is blue. I like the sky and the sea. Blue makes me feel calm.', 'A1', 1, 9, 17, '[{"index": 0, "transcript": "My favorite color is blue.", "start_ms": 0, "end_ms": 2000}, {"index": 1, "transcript": "I like the sky and the sea.", "start_ms": 2000, "end_ms": 4800}, {"index": 2, "transcript": "Blue makes me feel calm.", "start_ms": 4800, "end_ms": 6800}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'podcasts'), 'Podcast: How to Say Thank You', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A1/podcasts/ex-podcast-A1-003.mp3', 'It is important to say thank you. When someone helps you, always be grateful.', 'A1', 1, 7, 14, '[{"index": 0, "transcript": "It is important to say thank you.", "start_ms": 0, "end_ms": 2800}, {"index": 1, "transcript": "When someone helps you, always be grateful.", "start_ms": 2800, "end_ms": 5600}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'podcasts'), 'Podcast: Weekend Fun', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A1/podcasts/ex-podcast-A1-004.mp3', 'On the weekend, I like to go to the park. I play with my dog and read books.', 'A1', 1, 7, 18, '[{"index": 0, "transcript": "On the weekend, I like to go to the park.", "start_ms": 0, "end_ms": 4000}, {"index": 1, "transcript": "I play with my dog and read books.", "start_ms": 4000, "end_ms": 7200}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'podcasts'), 'Podcast: Good Night Story', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A1/podcasts/ex-podcast-A1-005.mp3', 'Once upon a time, there was a little cat. The cat lived in a big house near a river.', 'A1', 1, 8, 19, '[{"index": 0, "transcript": "Once upon a time, there was a little cat.", "start_ms": 0, "end_ms": 3600}, {"index": 1, "transcript": "The cat lived in a big house near a river.", "start_ms": 3600, "end_ms": 7600}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'podcasts'), 'Podcast: My Daily Morning Routine', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A2/podcasts/ex-podcast-A2-001.mp3', 'I usually wake up at seven, have breakfast, and then walk to the office. On the way, I stop at a small coffee shop and get a latte. The barista knows my order because I go there every single day. It takes me about twenty minutes to walk from my apartment to work.', 'A2', 2, 19, 53, '[{"index": 0, "transcript": "I usually wake up at seven, have breakfast, and then walk to the office.", "start_ms": 0, "end_ms": 5600}, {"index": 1, "transcript": "On the way, I stop at a small coffee shop and get a latte.", "start_ms": 5600, "end_ms": 11200}, {"index": 2, "transcript": "The barista knows my order because I go there every single day.", "start_ms": 11200, "end_ms": 16000}, {"index": 3, "transcript": "It takes me about twenty minutes to walk from my apartment to work.", "start_ms": 16000, "end_ms": 21200}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'podcasts'), 'Podcast: First Time Cooking', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A2/podcasts/ex-podcast-A2-002.mp3', 'Last night I tried to cook dinner for my family for the first time. I chose a simple pasta recipe that I found on the internet. Everything was going well until I forgot to set the timer and the pasta was overcooked. My family still said it was delicious, but I think they were just being nice to me.', 'A2', 2, 21, 59, '[{"index": 0, "transcript": "Last night I tried to cook dinner for my family for the first time.", "start_ms": 0, "end_ms": 5600}, {"index": 1, "transcript": "I chose a simple pasta recipe that I found on the internet.", "start_ms": 5600, "end_ms": 10400}, {"index": 2, "transcript": "Everything was going well until I forgot to set the timer and the pasta was overcooked.", "start_ms": 10400, "end_ms": 16800}, {"index": 3, "transcript": "My family still said it was delicious, but I think they were just being nice to me.", "start_ms": 16800, "end_ms": 23600}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'podcasts'), 'Podcast: Learning to Swim', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A2/podcasts/ex-podcast-A2-003.mp3', 'When I was ten years old, my father taught me how to swim in the ocean near our village. At first I was very scared because the waves were so big and the water was very cold. But after a few lessons, I started to feel more comfortable and now swimming is one of my favorite activities.', 'A2', 2, 19, 57, '[{"index": 0, "transcript": "When I was ten years old, my father taught me how to swim in the ocean near our village.", "start_ms": 0, "end_ms": 7600}, {"index": 1, "transcript": "At first I was very scared because the waves were so big and the water was very cold.", "start_ms": 7600, "end_ms": 14800}, {"index": 2, "transcript": "But after a few lessons, I started to feel more comfortable and now swimming is one of my favorite activities.", "start_ms": 14800, "end_ms": 22800}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'podcasts'), 'Podcast: Travel to Japan', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A2/podcasts/ex-podcast-A2-004.mp3', 'My best trip ever was to Japan last spring. I visited Tokyo, Kyoto, and Osaka in ten days. The food was absolutely amazing, especially the sushi and ramen. The people were very polite and helpful. Even though I could not speak Japanese, I managed to get around using simple English and a translation app on my phone.', 'A2', 2, 26, 57, '[{"index": 0, "transcript": "My best trip ever was to Japan last spring.", "start_ms": 0, "end_ms": 3600}, {"index": 1, "transcript": "I visited Tokyo, Kyoto, and Osaka in ten days.", "start_ms": 3600, "end_ms": 7200}, {"index": 2, "transcript": "The food was absolutely amazing, especially the sushi and ramen.", "start_ms": 7200, "end_ms": 11200}, {"index": 3, "transcript": "The people were very polite and helpful.", "start_ms": 11200, "end_ms": 14000}, {"index": 4, "transcript": "Even though I could not speak Japanese, I managed to get around using simple English and a translation app on my phone.", "start_ms": 14000, "end_ms": 22800}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'podcasts'), 'Podcast: My Pet Dog Story', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/A2/podcasts/ex-podcast-A2-005.mp3', 'I adopted my dog Max from an animal shelter three years ago. He was very thin and scared when I first brought him home. It took several weeks for him to trust me, but now he follows me everywhere and sleeps at the end of my bed every night. Having a pet has taught me a lot about patience and responsibility.', 'A2', 2, 21, 61, '[{"index": 0, "transcript": "I adopted my dog Max from an animal shelter three years ago.", "start_ms": 0, "end_ms": 4800}, {"index": 1, "transcript": "He was very thin and scared when I first brought him home.", "start_ms": 4800, "end_ms": 9600}, {"index": 2, "transcript": "It took several weeks for him to trust me, but now he follows me everywhere and sleeps at the end of my bed every night.", "start_ms": 9600, "end_ms": 19600}, {"index": 3, "transcript": "Having a pet has taught me a lot about patience and responsibility.", "start_ms": 19600, "end_ms": 24400}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'podcasts'), 'Podcast: The Art of Language Learning', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B1/podcasts/ex-podcast-B1-001.mp3', 'One of the best ways to learn a new language is to practice listening every day, even if it is just for fifteen or twenty minutes. Research has shown that consistent daily exposure to a language is more effective than long study sessions that happen only once or twice a week. The key is to find content that is slightly above your current level so that you are challenged but not overwhelmed.', 'B1', 3, 22, 72, '[{"index": 0, "transcript": "One of the best ways to learn a new language is to practice listening every day, even if it is just for fifteen or twenty minutes.", "start_ms": 0, "end_ms": 10400}, {"index": 1, "transcript": "Research has shown that consistent daily exposure to a language is more effective than long study sessions that happen only once or twice a week.", "start_ms": 10400, "end_ms": 20400}, {"index": 2, "transcript": "The key is to find content that is slightly above your current level so that you are challenged but not overwhelmed.", "start_ms": 20400, "end_ms": 28800}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'podcasts'), 'Podcast: Minimalism and Happiness', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B1/podcasts/ex-podcast-B1-002.mp3', 'The minimalist movement has gained significant popularity in recent years, with millions of people around the world deciding to own fewer things in pursuit of a more meaningful and less stressful life. Proponents argue that our consumer culture encourages us to accumulate possessions we do not actually need, creating clutter that occupies both physical space and mental bandwidth.', 'B1', 3, 23, 58, '[{"index": 0, "transcript": "The minimalist movement has gained significant popularity in recent years, with millions of people around the world deciding to own fewer things in pursuit of a more meaningful and less stressful life.", "start_ms": 0, "end_ms": 12800}, {"index": 1, "transcript": "Proponents argue that our consumer culture encourages us to accumulate possessions we do not actually need, creating clutter that occupies both physical space and mental bandwidth.", "start_ms": 12800, "end_ms": 23200}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'podcasts'), 'Podcast: Sleep Science', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B1/podcasts/ex-podcast-B1-003.mp3', 'Scientists have discovered that the quality of our sleep is influenced not only by how many hours we spend in bed but also by a complex set of factors including room temperature, exposure to blue light from electronic devices, caffeine consumption patterns, and the consistency of our sleep schedule. The circadian rhythm, which is essentially our body''s internal clock, responds strongly to light cues from the environment.', 'B1', 3, 24, 67, '[{"index": 0, "transcript": "Scientists have discovered that the quality of our sleep is influenced not only by how many hours we spend in bed but also by a complex set of factors including room temperature, exposure to blue light from electronic devices, caffeine consumption patterns, and the consistency of our sleep schedule.", "start_ms": 0, "end_ms": 19600}, {"index": 1, "transcript": "The circadian rhythm, which is essentially our body''s internal clock, responds strongly to light cues from the environment.", "start_ms": 19600, "end_ms": 26800}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'podcasts'), 'Podcast: The Psychology of Motivation', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B1/podcasts/ex-podcast-B1-004.mp3', 'Why do some people seem to have an endless supply of motivation while others struggle to get through even basic daily tasks? Psychologists have identified two primary types of motivation that drive human behavior. Extrinsic motivation comes from external rewards such as money, praise, or recognition, while intrinsic motivation arises from the internal satisfaction of doing something you find genuinely interesting or meaningful.', 'B1', 3, 27, 63, '[{"index": 0, "transcript": "Why do some people seem to have an endless supply of motivation while others struggle to get through even basic daily tasks?", "start_ms": 0, "end_ms": 8800}, {"index": 1, "transcript": "Psychologists have identified two primary types of motivation that drive human behavior.", "start_ms": 8800, "end_ms": 13600}, {"index": 2, "transcript": "Extrinsic motivation comes from external rewards such as money, praise, or recognition, while intrinsic motivation arises from the internal satisfaction of doing something you find genuinely interesting or meaningful.", "start_ms": 13600, "end_ms": 25200}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'podcasts'), 'Podcast: Coffee Culture Around the World', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B1/podcasts/ex-podcast-B1-005.mp3', 'The way people drink coffee varies dramatically from country to country, reflecting deep cultural values and social traditions that go far beyond mere beverage preference. In Italy, espresso is consumed standing at the bar in a brief social ritual that rarely lasts more than five minutes. In Ethiopia, where coffee was originally discovered, the traditional coffee ceremony can take up to three hours. In Vietnam, egg coffee blends strong drip coffee with sweetened egg yolk to create a rich custard-like drink.', 'B1', 3, 31, 81, '[{"index": 0, "transcript": "The way people drink coffee varies dramatically from country to country, reflecting deep cultural values and social traditions that go far beyond mere beverage preference.", "start_ms": 0, "end_ms": 10000}, {"index": 1, "transcript": "In Italy, espresso is consumed standing at the bar in a brief social ritual that rarely lasts more than five minutes.", "start_ms": 10000, "end_ms": 18400}, {"index": 2, "transcript": "In Ethiopia, where coffee was originally discovered, the traditional coffee ceremony can take up to three hours.", "start_ms": 18400, "end_ms": 25200}, {"index": 3, "transcript": "In Vietnam, egg coffee blends strong drip coffee with sweetened egg yolk to create a rich custard-like drink.", "start_ms": 25200, "end_ms": 32400}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'podcasts'), 'Podcast: The Future of Remote Work', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B2/podcasts/ex-podcast-B2-001.mp3', 'The shift to remote work has fundamentally changed how organizations approach collaboration, with many companies now investing heavily in digital tools to maintain productivity and team cohesion across distributed workforces. What began as a temporary response to a global health crisis has evolved into a permanent restructuring of the relationship between employers and employees, with recent surveys indicating that approximately sixty five percent of knowledge workers express a strong preference for hybrid arrangements.', 'B2', 4, 26, 73, '[{"index": 0, "transcript": "The shift to remote work has fundamentally changed how organizations approach collaboration, with many companies now investing heavily in digital tools to maintain productivity and team cohesion across distributed workforces.", "start_ms": 0, "end_ms": 12000}, {"index": 1, "transcript": "What began as a temporary response to a global health crisis has evolved into a permanent restructuring of the relationship between employers and employees, with recent surveys indicating that approximately sixty five percent of knowledge workers express a strong preference for hybrid arrangements.", "start_ms": 12000, "end_ms": 29200}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'podcasts'), 'Podcast: Gut Health and the Microbiome', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B2/podcasts/ex-podcast-B2-002.mp3', 'The emerging science of the gut microbiome is challenging long held assumptions about the relationship between nutrition, mental health, and overall wellbeing in ways that may fundamentally reshape how we approach medicine in the coming decades. Your digestive system contains approximately one hundred trillion microorganisms representing thousands of distinct species, collectively weighing roughly two kilograms and performing metabolic functions so essential to human survival that some researchers have begun referring to the microbiome as a virtual organ.', 'B2', 4, 30, 77, '[{"index": 0, "transcript": "The emerging science of the gut microbiome is challenging long held assumptions about the relationship between nutrition, mental health, and overall wellbeing in ways that may fundamentally reshape how we approach medicine in the coming decades.", "start_ms": 0, "end_ms": 14400}, {"index": 1, "transcript": "Your digestive system contains approximately one hundred trillion microorganisms representing thousands of distinct species, collectively weighing roughly two kilograms and performing metabolic functions so essential to human survival that some researchers have begun referring to the microbiome as a virtual organ.", "start_ms": 14400, "end_ms": 30800}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'podcasts'), 'Podcast: The History of Money', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B2/podcasts/ex-podcast-B2-003.mp3', 'The evolution of money from physical commodity to abstract digital representation constitutes one of the most fascinating and consequential transformations in human history, yet most people give remarkably little thought to the nature of the medium through which virtually all economic activity is conducted. For the vast majority of recorded history, money took the form of objects with intrinsic value, typically precious metals whose scarcity and durability made them practical stores of wealth.', 'B2', 4, 25, 73, '[{"index": 0, "transcript": "The evolution of money from physical commodity to abstract digital representation constitutes one of the most fascinating and consequential transformations in human history, yet most people give remarkably little thought to the nature of the medium through which virtually all economic activity is conducted.", "start_ms": 0, "end_ms": 17600}, {"index": 1, "transcript": "For the vast majority of recorded history, money took the form of objects with intrinsic value, typically precious metals whose scarcity and durability made them practical stores of wealth.", "start_ms": 17600, "end_ms": 29200}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'podcasts'), 'Podcast: Architecture and Psychology', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B2/podcasts/ex-podcast-B2-004.mp3', 'The buildings we inhabit exert a far more profound influence on our psychological states and social behaviors than most people consciously recognize, a relationship that the field of environmental psychology has been documenting with increasing precision over the past four decades. Studies have consistently demonstrated that factors as seemingly mundane as ceiling height, natural light exposure, window views, and the ratio of private to communal spaces significantly affect occupants'' stress levels, creative output, and social interaction patterns.', 'B2', 4, 31, 77, '[{"index": 0, "transcript": "The buildings we inhabit exert a far more profound influence on our psychological states and social behaviors than most people consciously recognize, a relationship that the field of environmental psychology has been documenting with increasing precision over the past four decades.", "start_ms": 0, "end_ms": 16400}, {"index": 1, "transcript": "Studies have consistently demonstrated that factors as seemingly mundane as ceiling height, natural light exposure, window views, and the ratio of private to communal spaces significantly affect occupants'' stress levels, creative output, and social interaction patterns.", "start_ms": 16400, "end_ms": 30800}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'podcasts'), 'Podcast: AI Ethics Deep Dive', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/B2/podcasts/ex-podcast-B2-005.mp3', 'As artificial intelligence systems become increasingly integrated into decision-making processes across healthcare, finance, and criminal justice, the question of algorithmic accountability and transparency has emerged as one of the most pressing ethical dilemmas of our generation. The fundamental challenge lies in the inherent opacity of deep learning systems, whose decision-making processes involve millions of weighted connections that are essentially impossible for human observers to interpret or explain in any meaningful way.', 'B2', 4, 27, 71, '[{"index": 0, "transcript": "As artificial intelligence systems become increasingly integrated into decision-making processes across healthcare, finance, and criminal justice, the question of algorithmic accountability and transparency has emerged as one of the most pressing ethical dilemmas of our generation.", "start_ms": 0, "end_ms": 14400}, {"index": 1, "transcript": "The fundamental challenge lies in the inherent opacity of deep learning systems, whose decision-making processes involve millions of weighted connections that are essentially impossible for human observers to interpret or explain in any meaningful way.", "start_ms": 14400, "end_ms": 28400}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'podcasts'), 'Podcast: The Paradox of Progress', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/C1/podcasts/ex-podcast-C1-001.mp3', 'The contemporary discourse surrounding technological progress is characterized by a peculiar cognitive dissonance that reveals something essential about the human relationship to change and uncertainty. On one hand, we celebrate innovation with an almost religious fervor, constructing elaborate narratives of linear advancement in which each generation stands upon the shoulders of its predecessors to reach ever greater heights of material prosperity, medical capability, and computational power. On the other hand, anxiety about the trajectory of technological development has reached levels not seen since the atomic age.', 'C1', 5, 31, 86, '[{"index": 0, "transcript": "The contemporary discourse surrounding technological progress is characterized by a peculiar cognitive dissonance that reveals something essential about the human relationship to change and uncertainty.", "start_ms": 0, "end_ms": 10000}, {"index": 1, "transcript": "On one hand, we celebrate innovation with an almost religious fervor, constructing elaborate narratives of linear advancement in which each generation stands upon the shoulders of its predecessors to reach ever greater heights of material prosperity, medical capability, and computational power.", "start_ms": 10000, "end_ms": 26400}, {"index": 2, "transcript": "On the other hand, anxiety about the trajectory of technological development has reached levels not seen since the atomic age.", "start_ms": 26400, "end_ms": 34400}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'podcasts'), 'Podcast: Consciousness and Free Will', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/C1/podcasts/ex-podcast-C1-002.mp3', 'The philosophical debate surrounding free will has acquired an entirely new dimension in light of neuroscientific discoveries that appear to challenge the intuitive sense of agency that most human beings experience as a fundamental feature of their conscious existence. Benjamin Libet''s pioneering experiments in the nineteen eighties demonstrated that measurable brain activity associated with voluntary motor decisions precedes the conscious awareness of having made a decision by approximately three hundred and fifty milliseconds, a finding that has been replicated by subsequent researchers using increasingly sophisticated neuroimaging technologies.', 'C1', 5, 31, 87, '[{"index": 0, "transcript": "The philosophical debate surrounding free will has acquired an entirely new dimension in light of neuroscientific discoveries that appear to challenge the intuitive sense of agency that most human beings experience as a fundamental feature of their conscious existence.", "start_ms": 0, "end_ms": 15600}, {"index": 1, "transcript": "Benjamin Libet''s pioneering experiments in the nineteen eighties demonstrated that measurable brain activity associated with voluntary motor decisions precedes the conscious awareness of having made a decision by approximately three hundred and fifty milliseconds, a finding that has been replicated by subsequent researchers using increasingly sophisticated neuroimaging technologies.", "start_ms": 15600, "end_ms": 34800}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'podcasts'), 'Podcast: The Death of Expertise', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/C1/podcasts/ex-podcast-C1-003.mp3', 'The erosion of institutional authority and expert credibility that has characterized the first quarter of the twenty first century represents not merely a cultural trend to be analyzed and discussed but a genuine epistemic crisis with potentially catastrophic consequences for the functioning of democratic societies that depend upon an informed citizenry capable of distinguishing reliable knowledge from sophisticated disinformation. The democratization of information that the internet was supposed to deliver has instead produced what the philosopher Tom Nichols aptly describes as the death of expertise, a cultural environment in which the uninformed opinion of a random individual with an internet connection is treated as epistemically equivalent to the considered judgment of someone who has dedicated decades to the rigorous study of a particular subject.', 'C1', 5, 39, 124, '[{"index": 0, "transcript": "The erosion of institutional authority and expert credibility that has characterized the first quarter of the twenty first century represents not merely a cultural trend to be analyzed and discussed but a genuine epistemic crisis with potentially catastrophic consequences for the functioning of democratic societies that depend upon an informed citizenry capable of distinguishing reliable knowledge from sophisticated disinformation.", "start_ms": 0, "end_ms": 23600}, {"index": 1, "transcript": "The democratization of information that the internet was supposed to deliver has instead produced what the philosopher Tom Nichols aptly describes as the death of expertise, a cultural environment in which the uninformed opinion of a random individual with an internet connection is treated as epistemically equivalent to the considered judgment of someone who has dedicated decades to the rigorous study of a particular subject.", "start_ms": 23600, "end_ms": 49600}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'podcasts'), 'Podcast: Urban Planning and Human Flourishing', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/C1/podcasts/ex-podcast-C1-004.mp3', 'The discipline of urban planning stands at a critical inflection point, confronting the increasingly urgent recognition that the car-centric development paradigm that has dominated metropolitan design since the mid-twentieth century has produced physical environments that are demonstrably hostile to human health, social connection, and ecological sustainability on virtually every measurable dimension. The suburban sprawl model that defined American and increasingly global urban development for the past seven decades was predicated on assumptions about energy costs, demographic preferences, and environmental capacity that have proven spectacularly wrong.', 'C1', 5, 33, 85, '[{"index": 0, "transcript": "The discipline of urban planning stands at a critical inflection point, confronting the increasingly urgent recognition that the car-centric development paradigm that has dominated metropolitan design since the mid-twentieth century has produced physical environments that are demonstrably hostile to human health, social connection, and ecological sustainability on virtually every measurable dimension.", "start_ms": 0, "end_ms": 20400}, {"index": 1, "transcript": "The suburban sprawl model that defined American and increasingly global urban development for the past seven decades was predicated on assumptions about energy costs, demographic preferences, and environmental capacity that have proven spectacularly wrong.", "start_ms": 20400, "end_ms": 34000}]'::jsonb);
INSERT INTO public.exercises (category_id, title, audio_url, transcript, cefr_level, difficulty, duration_seconds, word_count, chunks) VALUES ((SELECT id FROM public.exercise_categories WHERE slug = 'podcasts'), 'Podcast: The Future of Democracy', 'https://YOUR_PROJECT.supabase.co/storage/v1/object/public/audio/C1/podcasts/ex-podcast-C1-005.mp3', 'The proposition that liberal democracy represents, as Francis Fukuyama famously declared in nineteen eighty nine, the endpoint of humanity''s ideological evolution, has been subjected to a relentless series of empirical challenges over the past two decades that have exposed the fragility of institutions many observers had presumed to be permanent features of the political landscape in developed nations. The rise of authoritarian populism across multiple continents, the weaponization of social media for political manipulation, the erosion of shared epistemic foundations that enable productive democratic deliberation, and the demonstrated incapacity of democratic systems to respond effectively to slow-moving existential threats such as climate change and biodiversity loss have collectively generated what political theorists now characterize as a crisis of democratic legitimacy.', 'C1', 5, 43, 120, '[{"index": 0, "transcript": "The proposition that liberal democracy represents, as Francis Fukuyama famously declared in nineteen eighty nine, the endpoint of humanity''s ideological evolution, has been subjected to a relentless series of empirical challenges over the past two decades that have exposed the fragility of institutions many observers had presumed to be permanent features of the political landscape in developed nations.", "start_ms": 0, "end_ms": 23200}, {"index": 1, "transcript": "The rise of authoritarian populism across multiple continents, the weaponization of social media for political manipulation, the erosion of shared epistemic foundations that enable productive democratic deliberation, and the demonstrated incapacity of democratic systems to respond effectively to slow-moving existential threats such as climate change and biodiversity loss have collectively generated what political theorists now characterize as a crisis of democratic legitimacy.", "start_ms": 23200, "end_ms": 48000}]'::jsonb);
